const URL_ACCESS_KEYS = "https://raw.githubusercontent.com/" + GITHUB_USER + "/" + GITHUB_REPO + "/refs/heads/main/" + GITHUB_SET_JSON_FILE;
const URL_ADM_KEYS = "https://raw.githubusercontent.com/" + GITHUB_USER + "/" + GITHUB_REPO + "/refs/heads/main/adm-set.json";
/** Limit czasu (ms) na pobranie list kluczy */
const KEYS_FETCH_TIMEOUT_MS = 10000;

function fetchWithTimeout(url, ms) {
    return Promise.race([
        fetch(url),
        new Promise((_, reject) => setTimeout(() => reject(new Error("timeout")), ms)),
    ]);
}

function parseKeyList(data, ...keyNames) {
    if (!data || typeof data !== "object") return [];
    for (const name of keyNames) {
        const arr = data[name];
        if (Array.isArray(arr)) {
            return arr.map((x) => String(x).trim()).filter(Boolean);
        }
    }
    return [];
}

function parseKeysPayload(data) {
    const list = Array.isArray(data) ? data : (data && Array.isArray(data.items) ? data.items : []);
    const hasNewFormat = list.length > 0 && list.some((x) => x && ((x.key_sd ?? x.key_SD) != null || (x.key_adm ?? x.key_ADM) != null));
    if (hasNewFormat) {
        return {
            allowedKeys: list.map((x) => String((x.key_sd ?? x.key_SD) ?? "").trim()).filter(Boolean),
            allowedAdmKeys: list.map((x) => String((x.key_adm ?? x.key_ADM) ?? "").trim()).filter(Boolean),
            needAdmFetch: false,
        };
    }
    return {
        allowedKeys: parseKeyList(data, "keys"),
        allowedAdmKeys: [],
        needAdmFetch: true,
    };
}

const ACCESS_KEY_STORAGE = "accessKey";
const ACCESS_KEY_DISPLAY_STORAGE = "accessKeyDisplay";
const ACTIVE_KEY_FEEDBACK_STORAGE = "activeAccessKey";
const VALID_ACCESS_KEY = "";
const REQUIRE_ACCESS_EVERY_LOAD = false;
const USED_KEYS_STORAGE = "usedAccessKeys";
const ADMIN_RESET_KEY = "";

function getUsedKeys() {
    try {
        const raw = localStorage.getItem(USED_KEYS_STORAGE);
        if (!raw) return [];
        const arr = JSON.parse(raw);
        return Array.isArray(arr) ? arr : [];
    } catch (e) {
        return [];
    }
}

function addUsedKey(key) {
    if (!key) return;
    const used = getUsedKeys();
    if (used.includes(key)) return;
    used.push(key);
    try {
        localStorage.setItem(USED_KEYS_STORAGE, JSON.stringify(used));
    } catch (e) { }
}

function clearUsedKeys() {
    try {
        localStorage.removeItem(USED_KEYS_STORAGE);
    } catch (e) { }
}

function updateHeaderActiveKey() {
    const el = document.getElementById("active-key-display-header");
    if (!el) return;
    try {
        const key = localStorage.getItem(ACCESS_KEY_DISPLAY_STORAGE) || localStorage.getItem(ACCESS_KEY_STORAGE);
        el.textContent = key ? `KEY: ${key}` : "UNAUTHORIZED";
    } catch (e) {
        el.textContent = "ERR";
    }
}

// --- STATE ---
let scheduleData = null;
let currentDayIndex = 0;
let currentView = "daily";

// --- ELEMENTS ---
const loader = document.getElementById("loader");
const themeIcon = document.getElementById("theme-icon");
const resetDayBtn = document.querySelector(".reset-day-btn");

// Views
const viewDaily = document.getElementById("view-daily");
const viewIndividual = document.getElementById("view-individual");
const controlsDaily = document.getElementById("controls-daily");
const controlsIndividual = document.getElementById("controls-individual");
const btnViewDaily = document.getElementById("btn-view-daily");
const btnViewIndividual = document.getElementById("btn-view-individual");

// Individual Components
const workerSelectDisplay = document.getElementById("worker-select-display");
const workerSelectDropdown = document.getElementById("worker-select-dropdown");
const individualList = document.getElementById("individual-list");
let selectedWorkerId = null;

// Daily Components
const list1 = document.getElementById("list-1");
const listP1 = document.getElementById("list-p1");
const containerP1 = document.getElementById("container-p1");

const list2 = document.getElementById("list-2");
const listP2 = document.getElementById("list-p2");
const containerP2 = document.getElementById("container-p2");

const listOther = document.getElementById("list-other");
const listAbsent = document.getElementById("list-absent");

const labelDate = document.getElementById("current-date-display");
const labelName = document.getElementById("current-day-name");
const labelMonth = document.getElementById("month-label");

const count1El = document.getElementById("count-1");
const count2El = document.getElementById("count-2");
const countOtherEl = document.getElementById("count-other");
const countAbsentEl = document.getElementById("count-absent");

const dayOffsetMap = { PN: 0, WT: 1, SR: 2, ŚR: 2, CZ: 3, PT: 4, SO: 5, ND: 6 };

function getWorkerGroupInfo(id) {
    const workerId = parseInt(id);
    let result = { className: "", name: "", code: "" };
    if (settingsData && settingsData.groups) {
        const group = settingsData.groups.find(
            (g) => workerId >= g.min && workerId <= g.max,
        );
        if (group) {
            result.className = `group-${group.code}`;
            result.name = group.name;
            result.code = group.code;
            result.badgeHtml = `<span class="group-badge ${result.className}"></span>`;
        }
    }
    return result;
}

// --- LOGIC: VIEW & RENDER ---

function switchView(viewName) {
    currentView = viewName;
    const viewSwitcherTabs = document.getElementById("view-switcher-tabs");
    const viewSwitcherBack = document.getElementById("view-switcher-back");

    if (viewName === "daily") {
        viewDaily.classList.remove("hidden");
        viewIndividual.classList.add("hidden");
        controlsDaily.classList.remove("hidden");
        controlsIndividual.classList.add("hidden");
        btnViewDaily.classList.add("active");
        btnViewIndividual.classList.remove("active");
        viewSwitcherTabs.classList.remove("hidden");
        viewSwitcherBack.classList.add("hidden");
    } else {
        viewDaily.classList.add("hidden");
        viewIndividual.classList.remove("hidden");
        controlsDaily.classList.add("hidden");
        controlsIndividual.classList.remove("hidden");
        btnViewDaily.classList.remove("active");
        btnViewIndividual.classList.add("active");
        viewSwitcherTabs.classList.add("hidden");
        viewSwitcherBack.classList.remove("hidden");
        if (selectedWorkerId) renderIndividualSchedule();
    }
    lucide.createIcons();
}

function populateWorkerSelect() {
    if (!scheduleData) return;
    const sortedWorkers = [...scheduleData.workers].sort(
        (a, b) => parseInt(a.id) - parseInt(b.id),
    );

    workerSelectDropdown.innerHTML = "";

    sortedWorkers.forEach((worker) => {
        const groupInfo = getWorkerGroupInfo(worker.id);
        const groupBadge = groupInfo.badgeHtml || "";
        const option = document.createElement("div");
        option.className = "custom-select-option";
        option.dataset.workerId = worker.id;
        option.innerHTML = `
                  <div class="flex items-center gap-2">
                    <div class="avatar-wrapper">
                      ${worker.name.charAt(0)}
                      ${groupBadge ? `<div class="badge-wrapper">${groupBadge}</div>` : ""}
                    </div>
                    <span>${worker.name}</span>
                  </div>
                `;
        option.onclick = () => selectWorker(worker.id, worker.name, groupBadge);
        workerSelectDropdown.appendChild(option);
    });

    workerSelectDisplay.onclick = () => {
        workerSelectDropdown.classList.toggle("hidden");
    };

    document.addEventListener("click", (e) => {
        if (!e.target.closest(".custom-select-wrapper")) {
            workerSelectDropdown.classList.add("hidden");
        }
    });
}

function selectWorker(workerId, workerName, groupBadge) {
    selectedWorkerId = workerId;
    workerSelectDisplay.querySelector(".card-name").innerHTML = workerName;
    workerSelectDropdown.classList.add("hidden");
    renderIndividualSchedule();
}

function renderIndividualSchedule() {
    if (!selectedWorkerId || !scheduleData) return;
    const worker = scheduleData.workers.find((w) => w.id == selectedWorkerId);
    if (!worker) return;

    individualList.innerHTML = "";
    const days = scheduleData.meta.days;
    const weekdays = scheduleData.meta.weekdays;
    const groupInfo = getWorkerGroupInfo(worker.id);
    const groupBadge = groupInfo.badgeHtml || "";
    const groupName = groupInfo.name || "UNASSIGNED";

    let totalHours = 0, shift1Count = 0, shift2Count = 0, shiftP1Count = 0, shiftP2Count = 0, otherShifts = 0, workDays = 0;

    worker.shifts.forEach((shift) => {
        if (!shift) return;
        const code = shift.toUpperCase();
        if (["X", "U", "ZW", "L4", "OPIEKA", "UW", "W", "NN", "CH", "WYP", "SZKOLENIE", "URLOP"].includes(code)) return;
        workDays++;
        if (code === "P1" || code === "NP1") { shiftP1Count++; totalHours += 12; }
        else if (code === "P2" || code === "NP2") { shiftP2Count++; totalHours += 12; }
        else if (code.includes("1")) { shift1Count++; totalHours += 12; }
        else if (code.includes("2")) { shift2Count++; totalHours += 12; }
        else { otherShifts++; totalHours += 8; }
    });

    const headerDiv = document.createElement("div");
    headerDiv.className = "worker-header";
    headerDiv.innerHTML = `
                  <div class="avatar-wrapper">
                    ${worker.name.charAt(0)}
                    <div class="badge-wrapper">${groupBadge}</div>
                  </div>
                  <div class="worker-info">
                    <div class="worker-info-name">${worker.name}</div>
                    <div class="worker-info-group">${groupName}</div>
                  </div>
                `;
    individualList.appendChild(headerDiv);

    const statsDiv1 = document.createElement("div");
    statsDiv1.className = "stats-grid-3";
    statsDiv1.innerHTML = `
                <div class="stat-item">
                  <span class="stat-value">${totalHours}h</span>
                  <span class="stat-label">TOTAL HOURS</span>
                </div>
                <div class="stat-item">
                  <span class="stat-value">${workDays}</span>
                  <span class="stat-label">ACTIVE DAYS</span>
                </div>
                <div class="stat-item">
                  <span class="stat-value">${otherShifts}</span>
                  <span class="stat-label">AUX SHIFTS</span>
                </div>
              `;
    individualList.appendChild(statsDiv1);

    const statsDiv2 = document.createElement("div");
    statsDiv2.className = "stats-grid-4";
    statsDiv2.innerHTML = `
                <div class="stat-item"><span class="stat-value">${shift1Count}</span><span class="stat-label">S1</span></div>
                <div class="stat-item"><span class="stat-value">${shift2Count}</span><span class="stat-label">S2</span></div>
                <div class="stat-item"><span class="stat-value">${shiftP1Count}</span><span class="stat-label">P1</span></div>
                <div class="stat-item"><span class="stat-value">${shiftP2Count}</span><span class="stat-label">P2</span></div>
              `;
    individualList.appendChild(statsDiv2);

    ["PN", "WT", "ŚR", "CZ", "PT", "SO", "ND"].forEach((dh) => {
        const hCell = document.createElement("div");
        hCell.className = "calendar-header-cell";
        hCell.innerText = dh;
        individualList.appendChild(hCell);
    });

    const firstDayWeekName = weekdays[0];
    const offset = dayOffsetMap[firstDayWeekName] || 0;
    for (let i = 0; i < offset; i++) {
        individualList.appendChild(document.createElement("div"));
    }

    const today = new Date().getDate().toString();
    days.forEach((dayNum, index) => {
        const shiftCode = worker.shifts[index];
        const weekday = weekdays[index];
        const row = document.createElement("div");
        row.className = "individual-row";
        if (dayNum == today) row.classList.add("current-day-highlight");
        if (weekday === "SO" || weekday === "ND") row.classList.add("weekend-row");

        let codeStyle = "color: var(--text-muted);";
        if (shiftCode) {
            const sc = shiftCode.toUpperCase();
            if (sc.includes("1")) codeStyle = "color: var(--blue-color); font-weight:bold;";
            if (sc.includes("2")) codeStyle = "color: var(--highlight-color); font-weight:bold;";
            if (["L4", "U", "X", "URLOP"].includes(sc)) codeStyle = "color: var(--danger-color);";
        }

        row.innerHTML = `
                    <div class="day-info">${dayNum}</div>
                    <div style="${codeStyle}">${shiftCode || "-"}</div>
                `;
        individualList.appendChild(row);
    });
}

function getShiftType(shiftCode) {
    if (!shiftCode || shiftCode === "" || shiftCode === "-") return "ABSENT";
    const code = shiftCode.toUpperCase();
    if (["X", "U", "ZW", "L4", "OPIEKA", "UW", "W", "NN", "CH", "WYP", "SZKOLENIE", "URLOP"].includes(code)) return "ABSENT";
    if (code === "P1" || code === "NP1") return "SHIFT_P1";
    if (code === "P2" || code === "NP2") return "SHIFT_P2";
    if (code.includes("1")) return "SHIFT_1";
    if (code.includes("2")) return "SHIFT_2";
    return "OTHER";
}

function createWorkerCard(worker, shiftCode, dayIndex) {
    const div = document.createElement("div");
    div.className = "tectonic-card";
    
    let badgeClass = "shift-tag";
    const sc = shiftCode.toUpperCase();
    if (sc === "P1" || sc === "NP1") badgeClass += " badge-shift-1";
    else if (sc === "P2" || sc === "NP2") badgeClass += " badge-shift-2";
    else if (sc.includes("1")) badgeClass += " badge-shift-1";
    else if (sc.includes("2")) badgeClass += " badge-shift-2";
    else if (["X", "U", "ZW", "L4", "OPIEKA", "UW", "W", "NN", "CH", "WYP", "SZKOLENIE", "URLOP"].includes(sc)) badgeClass += " badge-absent";
    else badgeClass += " style-shift-other";

    const groupInfo = getWorkerGroupInfo(worker.id);
    const groupBadge = groupInfo.badgeHtml || "";

    div.innerHTML = `
                <div class="card-meta">
                    <span>ID: ${worker.id}</span>
                </div>
                <div class="flex items-center gap-2" style="margin-bottom:0.75rem;">
                     <div class="avatar-wrapper">
                        ${worker.name.charAt(0)}
                        ${groupBadge ? `<div class="badge-wrapper">${groupBadge}</div>` : ""}
                    </div>
                    <span class="card-name" style="margin-bottom:0;">${worker.name}</span>
                </div>
                <div class="card-foot">
                    <div class="${badgeClass}">${shiftCode}</div>
                </div>
            `;
    div.onclick = () => {
        selectWorker(worker.id, worker.name, groupBadge);
        switchView("individual");
    };
    return div;
}

function renderSchedule() {
    if (!scheduleData) return;
    const dayNumber = scheduleData.meta.days[currentDayIndex];
    const dayName = scheduleData.meta.weekdays[currentDayIndex];
    const monthName = scheduleData.meta.month;

    labelDate.innerText = `${dayNumber}`;
    labelName.innerText = dayName;

    const today = new Date().getDate();
    labelMonth.innerHTML = `<span>DATE: ${today} ${monthName}</span>`;

    list1.innerHTML = ""; listP1.innerHTML = ""; list2.innerHTML = ""; listP2.innerHTML = "";
    listOther.innerHTML = ""; listAbsent.innerHTML = "";
    containerP1.classList.add("hidden"); containerP2.classList.add("hidden");

    let c1 = 0, cP1 = 0, c2 = 0, cP2 = 0, cO = 0, cAbsent = 0;

    scheduleData.workers.forEach((worker) => {
        const shiftCode = worker.shifts[currentDayIndex] || "";
        const type = getShiftType(shiftCode);
        const card = createWorkerCard(worker, shiftCode || "-", currentDayIndex);

        switch (type) {
            case "SHIFT_1": list1.appendChild(card); c1++; break;
            case "SHIFT_P1": listP1.appendChild(card); cP1++; break;
            case "SHIFT_2": list2.appendChild(card); c2++; break;
            case "SHIFT_P2": listP2.appendChild(card); cP2++; break;
            case "OTHER": listOther.appendChild(card); cO++; break;
            case "ABSENT": listAbsent.appendChild(card); cAbsent++; break;
        }
    });

    if (cP1 > 0) containerP1.classList.remove("hidden");
    if (cP2 > 0) containerP2.classList.remove("hidden");

    count1El.innerText = c1 + cP1;
    count2El.innerText = c2 + cP2;
    countOtherEl.innerText = cO;
    countAbsentEl.innerText = cAbsent;

    const emptyMsg = `<div class="tectonic-card" style="opacity:0.5; border-style:dashed;"><div class="card-meta">STATUS</div><span class="card-name">NO UNITS DEPLOYED</span></div>`;
    if (c1 === 0 && cP1 === 0) list1.innerHTML = emptyMsg;
    if (c2 === 0 && cP2 === 0) list2.innerHTML = emptyMsg;

    document.getElementById("section-other").style.display = cO === 0 ? "none" : "block";
    lucide.createIcons();
}

function changeDay(delta) {
    if (!scheduleData) return;
    const max = scheduleData.meta.days.length - 1;
    let newIndex = currentDayIndex + delta;
    if (newIndex < 0) newIndex = 0;
    if (newIndex > max) newIndex = max;
    currentDayIndex = newIndex;
    renderSchedule();
    updateResetDayButton();
}

function toggleAbsent() {
    const el = document.getElementById("list-absent");
    const text = document.getElementById("toggle-text");
    const isHidden = el.classList.contains("hidden");
    if (isHidden) {
        el.classList.remove("hidden");
        if (text) text.innerText = "HIDE";
    } else {
        el.classList.add("hidden");
        if (text) text.innerText = "SHOW";
    }
}

function goToToday() {
    if (!scheduleData) return;
    const today = new Date().getDate().toString();
    const idx = scheduleData.meta.days.findIndex((d) => d == today);
    if (idx !== -1) {
        currentDayIndex = idx;
        renderSchedule();
        updateResetDayButton();
    }
}

function updateResetDayButton() {
    if (!scheduleData || !resetDayBtn) return;
    const today = new Date().getDate().toString();
    const todayIndex = scheduleData.meta.days.findIndex((d) => d == today);
    if (todayIndex !== -1 && currentDayIndex !== todayIndex) {
        resetDayBtn.style.borderColor = "var(--highlight-color)";
    } else {
        resetDayBtn.style.borderColor = "transparent";
    }
}

// --- THEME ---
function initTheme() {
    const storedTheme = localStorage.getItem("app-theme");
    if (storedTheme === "light") {
        document.body.removeAttribute("theme");
    } else {
        document.body.setAttribute("theme", "dark");
    }
    lucide.createIcons();
}

function toggleTheme() {
    const body = document.body;
    if (body.getAttribute("theme") === "dark") {
        body.removeAttribute("theme");
        localStorage.setItem("app-theme", "light");
    } else {
        body.setAttribute("theme", "dark");
        localStorage.setItem("app-theme", "dark");
    }
}

// --- CLOCK ---
function updateClock() {
    const now = new Date();
    const h = String(now.getHours()).padStart(2, '0');
    const m = String(now.getMinutes()).padStart(2, '0');
    const s = String(now.getSeconds()).padStart(2, '0');
    const clock = document.getElementById('clock');
    if(clock) clock.textContent = `${h}:${m}:${s}`;
}
setInterval(updateClock, 1000);
updateClock();

// --- DATA LOADING & AUTH MOCKUP FOR UI ---
// To logika z Twojego pliku, skondensowana i wpięta w UI
function loadData() {
    const urlScheduleMain = `https://raw.githubusercontent.com/${GITHUB_USER}/${GITHUB_REPO}/refs/heads/main/${GITHUB_SCHEDULE_FILE}`;
    const urlScheduleMaster = `https://raw.githubusercontent.com/${GITHUB_USER}/${GITHUB_REPO}/refs/heads/master/${GITHUB_SCHEDULE_FILE}`;
    const urlSettingsMain = `https://raw.githubusercontent.com/${GITHUB_USER}/${GITHUB_REPO}/refs/heads/main/${GITHUB_SETTINGS_FILE}`;
    const urlSettingsMaster = `https://raw.githubusercontent.com/${GITHUB_USER}/${GITHUB_REPO}/refs/heads/master/${GITHUB_SETTINGS_FILE}`;

    const parseJsonResponse = (res) => res.text().then(text => JSON.parse(text));
    const fetchWithFallback = (urlMain, urlFallback) => fetch(urlMain).then(res => res.ok ? parseJsonResponse(res) : fetch(urlFallback).then(r => parseJsonResponse(r)));

    Promise.all([
        fetchWithFallback(urlScheduleMain, urlScheduleMaster),
        fetchWithFallback(urlSettingsMain, urlSettingsMaster).catch(() => ({ groups: [] }))
    ]).then(([schedData, settData]) => {
        scheduleData = schedData;
        window.settingsData = settData;
        loader.classList.add("hidden");
        viewDaily.classList.remove("hidden");
        populateWorkerSelect();
        goToToday();
        updateHeaderActiveKey();
    }).catch(err => {
        // ERROR UI
        loader.innerHTML = `
            <div class="tectonic-card" style="border-color: var(--danger-color)">
                <div class="card-meta" style="color: var(--danger-color)">SYSTEM CRITICAL</div>
                <span class="card-name">CONNECTION FAILURE</span>
                <div class="error-key-access-panel" style="margin-top:1rem;">
                    <p style="font-size:0.7rem;">${err.message}</p>
                    <button onclick="location.reload()" class="error-access-login-btn" style="margin-top:1rem;">REBOOT SYSTEM</button>
                </div>
            </div>
        `;
    });
}

document.addEventListener("DOMContentLoaded", () => {
    initTheme();
    loadData();
});

