/* --- INTEGRACJA TWOICH INSTRUKCJI --- */
* {
    user-select: none;
    /* Blokada zaznaczania */
    border-radius: 0 !important;
    /* Brak zaokrągleń */
    box-sizing: border-box;
}

:root {
    --neon-white: #ffffff;
    --bg-black: #000000;
    --dim-gray: #333333;
    --font-mono: "JetBrains Mono", "Share Tech Mono", monospace;
}

body {
    background-color: var(--bg-black);
    color: var(--neon-white);
    font-family: var(--font-mono);
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    margin: 0;
    text-transform: uppercase;
}

/* --- RAMA I EFEKTY --- */
.terminal-frame {
    border: 2px solid var(--neon-white);
    padding: 10px;
    width: 90vw;
    max-width: 800px;
    position: relative;
}

/* --- WYRAZISTA TYPOGRAFIA --- */
.massive-label {
    font-size: 5rem;
    font-weight: 900;
    line-height: 0.9;
    letter-spacing: -4px;
    margin: 0;
    background: var(--neon-white);
    color: var(--bg-black);
    padding: 0 10px;
    /* Pionowa orientacja wzorowana na 'KONCEPT' */
}

.sub-header-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    border: 1px solid var(--neon-white);
    margin-top: 10px;
    padding: 5px;
    font-weight: bold;
}

/* --- ELEMENTY GRAFICZNE --- */
.diagonal-pattern {
    height: 40px;
    background: repeating-linear-gradient(45deg,
            var(--neon-white),
            var(--neon-white) 2px,
            transparent 2px,
            transparent 8px);
    opacity: 0.4;
    margin: 10px 0;
}

.decorative-arrows {
    width: 60px;
    height: 15px;
    /* Styl strzałek z Twojego pliku */
    background-image: url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 20"><polygon points="0,0 20,10 0,20" fill="white"/><polygon points="30,0 50,10 30,20" fill="white"/><polygon points="60,0 80,10 60,20" fill="white"/></svg>');
    background-size: contain;
    background-repeat: no-repeat;
}

/* --- UKŁAD I BLOKI --- */
.content-grid {
    display: grid;
    grid-template-columns: 1fr 60px;
    gap: 15px;
    margin-top: 20px;
}

.data-block {
    border-left: 5px solid var(--neon-white);
    padding-left: 15px;

    & .active {
        background: var(--neon-white);
        color: var(--bg-black);
        padding: 0 5px;
    }
}

.side-panel {
    border-left: 1px solid var(--dim-gray);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-between;

    & .vertical-text {
        writing-mode: vertical-rl;
        font-size: 0.7rem;
        letter-spacing: 2px;
        color: var(--dim-gray);
    }
}

.bit-box {
    width: 12px;
    height: 12px;
    border: 1px solid var(--neon-white);
    margin-bottom: 5px;

    &.filled {
        background: var(--neon-white);
    }
}

 :root {
     --bg-void: #030407;
     --glass-base: rgba(15, 20, 30, 0.6);
     --glass-border: rgba(255, 255, 255, 0.08);
     --primary: #ff4d00;
     --primary-glow: rgba(255, 77, 0, 0.4);
     --accent: #00f2ff;
     --text-main: #e0e0e0;
     --text-dim: #808090;
     --font-sans: 'Plus Jakarta Sans', sans-serif;
     --font-mono: 'JetBrains Mono', monospace;

     --bg-d: #cc8a28;
     --bg-s: #0052cc;
     --bg-l: #5981cc;
     --bg-k: #cc6f44;
     --bg-m: #cccc00;
     --bg-y: #00cc00;

     --sb-1: #ff9d00;
     --sb-2: #3d5afe;
     --sb-p: #00e676;
     --sb-n: #f50057;
     --sb-x: #616161;
     --sb-u: #7c4dff;
     --sb-s: #00bcd4;
 }

 [data-theme="light"] {
     --bg-void: #f0f2f5;
     --glass-base: rgba(255, 255, 255, 0.7);
     --glass-border: rgba(0, 0, 0, 0.05);
     --text-main: #1a1a1a;
     --text-dim: #606070;
 }

 * {
     margin: 0;
     padding: 0;
     box-box: border-box;
 }

 body {
     background-color: var(--bg-void);
     color: var(--text-main);
     font-family: var(--font-sans);
     overflow: hidden;
     height: 100vh;
     width: 100vw;
 }

 /* --- MOLTEN REFRACTION BACKGROUND --- */
 .molten-bg {
     position: fixed;
     top: 0;
     left: 0;
     width: 100%;
     height: 100%;
     z-index: -1;
     overflow: hidden;
     filter: blur(60px) contrast(1.2);
 }

 .blob {
     position: absolute;
     width: 500px;
     height: 500px;
     background: linear-gradient(135deg, var(--primary), #ff0080);
     border-radius: 50%;
     opacity: 0.2;
     animation: drift 25s infinite alternate ease-in-out;
 }

 .blob.alt {
     background: linear-gradient(135deg, var(--accent), #7000ff);
     width: 700px;
     height: 700px;
     right: -100px;
     top: -100px;
     animation-duration: 35s;
 }

 @keyframes drift {
     from {
         transform: translate(-10%, -10%) rotate(0deg) scale(1);
     }

     to {
         transform: translate(20%, 30%) rotate(360deg) scale(1.2);
     }
 }

 /* --- SYSTEM LAYOUT --- */
 .app-shell {
     display: grid;
     grid-template-columns: 320px 1fr;
     grid-template-rows: 70px 1fr 40px;
     height: 100vh;
     gap: 1px;
     background: var(--glass-border);
 }

 /* Glass Panel Styling */
 .glass-panel {
     background: var(--glass-base);
     backdrop-filter: blur(20px) saturate(180%);
     -webkit-backdrop-filter: blur(20px) saturate(180%);
     border: 1px solid var(--glass-border);
     position: relative;
     overflow: hidden;
 }

 /* Top Bar */
 .top-bar {
     grid-column: 1 / -1;
     display: flex;
     align-items: center;
     padding: 0 30px;
     justify-content: space-between;
 }

 .sys-logo {
     font-weight: 800;
     letter-spacing: -1px;
     font-size: 20px;
     display: flex;
     align-items: center;
     gap: 12px;
 }

 .sys-logo span {
     color: var(--primary);
     text-shadow: 0 0 15px var(--primary-glow);
 }

 .top-bar-right {
     display: flex;
     align-items: center;
     gap: 24px;
 }

 /* Sidebar */
 .sidebar {
     display: flex;
     flex-direction: column;
     padding: 24px;
     gap: 20px;
     overflow-y: auto;
 }

 .search-container {
     position: relative;
 }

 .search-input {
     width: 100%;
     background: rgba(255, 255, 255, 0.05);
     border: 1px solid var(--glass-border);
     padding: 12px 16px;
     border-radius: 8px;
     color: white;
     font-family: var(--font-sans);
     outline: none;
     transition: border 0.3s;
 }

 .search-input:focus {
     border-color: var(--primary);
 }

 .nav-group {
     display: flex;
     flex-direction: column;
     gap: 4px;
 }

 .nav-item {
     padding: 12px 16px;
     border-radius: 8px;
     cursor: pointer;
     display: flex;
     align-items: center;
     gap: 12px;
     color: var(--text-dim);
     transition: 0.2s cubic-bezier(0.4, 0, 0.2, 1);
     font-weight: 500;
     font-size: 14px;
 }

 .nav-item:hover {
     background: rgba(255, 255, 255, 0.05);
     color: white;
 }

 .nav-item.active {
     background: rgba(255, 77, 0, 0.1);
     color: var(--primary);
     box-shadow: inset 0 0 0 1px var(--primary-glow);
 }

 /* Main Content */
 .main-view {
     overflow-y: auto;
     padding: 30px;
     background: radial-gradient(circle at top left, rgba(255, 255, 255, 0.02), transparent);
 }

 .view-pane {
     display: none;
     animation: fadeIn 0.4s ease-out;
 }

 .view-pane.active {
     display: block;
 }

 @keyframes fadeIn {
     from {
         opacity: 0;
         transform: translateY(10px);
     }

     to {
         opacity: 1;
         transform: translateY(0);
     }
 }

 /* Dashboard Cards */
 .dashboard-header {
     margin-bottom: 30px;
     display: flex;
     justify-content: space-between;
     align-items: flex-end;
 }

 .day-badge {
     font-family: var(--font-mono);
     font-size: 12px;
     color: var(--primary);
     text-transform: uppercase;
     letter-spacing: 2px;
     margin-bottom: 8px;
     display: block;
 }

 .huge-title {
     font-size: 42px;
     font-weight: 800;
     letter-spacing: -1.5px;
 }

 .shifts-grid {
     display: grid;
     grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
     gap: 20px;
 }

 .shift-card {
     background: rgba(255, 255, 255, 0.03);
     border: 1px solid var(--glass-border);
     border-radius: 16px;
     padding: 24px;
     transition: transform 0.3s;
 }

 .shift-card:hover {
     transform: translateY(-4px);
     border-color: rgba(255, 255, 255, 0.15);
 }

 .shift-header {
     display: flex;
     align-items: center;
     margin-bottom: 20px;
     border-bottom: 1px solid var(--glass-border);
     padding-bottom: 12px;
 }

 .shift-tag {
     padding: 4px 10px;
     border-radius: 4px;
     font-weight: 800;
     font-family: var(--font-mono);
     font-size: 14px;
     margin-right: 12px;
 }

 .worker-entry {
     display: flex;
     align-items: center;
     padding: 8px 0;
     font-size: 15px;
     border-bottom: 1px solid rgba(255, 255, 255, 0.02);
 }

 /* --- TABLES --- */
 .table-wrap {
     overflow-x: auto;
     border-radius: 12px;
     border: 1px solid var(--glass-border);
 }

 table {
     width: 100%;
     border-collapse: collapse;
     font-family: var(--font-sans);
     font-size: 13px;
 }

 th {
     background: rgba(255, 255, 255, 0.05);
     padding: 12px;
     text-align: center;
     color: var(--text-dim);
     font-weight: 600;
     border-bottom: 1px solid var(--glass-border);
 }

 td {
     padding: 8px;
     text-align: center;
     border: 1px solid var(--glass-border);
 }

 .cell-input {
     width: 100%;
     border: none;
     background: transparent;
     color: inherit;
     text-align: center;
     font-family: var(--font-mono);
     font-weight: bold;
     outline: none;
 }

 /* UI Colors */
 .sb-1 {
     background: var(--sb-1);
     color: #000;
 }

 .sb-2 {
     background: var(--sb-2);
     color: #fff;
 }

 .sb-p {
     background: var(--sb-p);
     color: #000;
 }

 .sb-n {
     background: var(--sb-n);
     color: #fff;
 }

 .sb-x {
     background: var(--sb-x);
     color: #fff;
 }

 .sb-u {
     background: var(--sb-u);
     color: #fff;
 }

 .sb-s {
     background: var(--sb-s);
     color: #000;
 }

 /* Icon Masking Engine */
 .sys-icon-mask {
     mask-image: var(--icon-url);
     -webkit-mask-image: var(--icon-url);
     mask-size: contain;
     -webkit-mask-size: contain;
     mask-repeat: no-repeat;
     -webkit-mask-repeat: no-repeat;
     background-color: var(--icon-color);
     display: inline-block;
 }

 /* Footer */
 .footer {
     grid-column: 1 / -1;
     display: flex;
     align-items: center;
     padding: 0 30px;
     font-family: var(--font-mono);
     font-size: 10px;
     color: var(--text-dim);
     justify-content: space-between;
     border-top: 1px solid var(--glass-border);
 }

 /* Modals */
 .sys-overlay {
     position: fixed;
     top: 0;
     left: 0;
     width: 100%;
     height: 100%;
     background: rgba(0, 0, 0, 0.8);
     backdrop-filter: blur(10px);
     z-index: 1000;
     display: none;
     align-items: center;
     justify-content: center;
 }

 .sys-modal {
     background: #0a0c10;
     border: 1px solid var(--primary);
     width: 500px;
     max-width: 90vw;
     border-radius: 12px;
     padding: 30px;
     box-shadow: 0 0 50px rgba(255, 77, 0, 0.2);
 }

 /* Utility buttons */
 .btn {
     background: transparent;
     border: 1px solid var(--glass-border);
     color: var(--text-main);
     padding: 8px 16px;
     border-radius: 6px;
     cursor: pointer;
     font-weight: 600;
     font-size: 12px;
     transition: 0.2s;
     display: flex;
     align-items: center;
     gap: 8px;
 }

 .btn:hover {
     background: rgba(255, 255, 255, 0.1);
 }

 .btn-active {
     border-color: var(--primary);
     color: var(--primary);
 }

 /* Dropdowns */
 .custom-select {
     position: relative;
     cursor: pointer;
 }

 .select-trigger {
     background: rgba(255, 255, 255, 0.05);
     border: 1px solid var(--glass-border);
     padding: 8px 16px;
     border-radius: 6px;
     font-size: 13px;
     display: flex;
     align-items: center;
     justify-content: space-between;
     min-width: 160px;
 }

 .select-options {
     position: absolute;
     top: 110%;
     left: 0;
     width: 100%;
     background: #111;
     border: 1px solid var(--glass-border);
     border-radius: 6px;
     display: none;
     z-index: 100;
     max-height: 250px;
     overflow-y: auto;
 }

 .select-options.show {
     display: block;
 }

 .option {
     padding: 10px 16px;
     transition: 0.2s;
     font-size: 13px;
 }

 .option:hover {
     background: var(--primary);
     color: white;
 }

 /* Notification */
 #sys-notify {
     position: fixed;
     bottom: 60px;
     right: 30px;
     background: #000;
     border-left: 4px solid var(--primary);
     padding: 16px 24px;
     font-family: var(--font-mono);
     font-size: 12px;
     transform: translateX(150%);
     transition: transform 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275);
     z-index: 2000;
     box-shadow: 0 10px 30px rgba(0, 0, 0, 0.5);
 }

 #sys-notify.active {
     transform: translateX(0);
 }

 /* Scrollbar */
 ::-webkit-scrollbar {
     width: 4px;
     height: 4px;
 }

 ::-webkit-scrollbar-thumb {
     background: var(--glass-border);
     border-radius: 10px;
 }

 ::-webkit-scrollbar-thumb:hover {
     background: var(--primary);
 }

 .loader-overlay {
     position: fixed;
     top: 0;
     left: 0;
     width: 100%;
     height: 100%;
     background: var(--bg-void);
     display: flex;
     align-items: center;
     justify-content: center;
     z-index: 9999;
 }

 .spinner {
     width: 40px;
     height: 40px;
     border: 3px solid rgba(255, 255, 255, 0.1);
     border-top-color: var(--primary);
     border-radius: 50%;
     animation: spin 1s linear infinite;
 }

 @keyframes spin {
     to {
         transform: rotate(360deg);
     }
 }

 .sys-mini-badge {
     font-size: 9px;
     padding: 1px 4px;
     border-radius: 2px;
     margin-left: 6px;
     font-weight: bold;
 }

 /* Calendar grid */
 .calendar-grid {
     display: grid;
     grid-template-columns: repeat(7, 1fr);
     gap: 4px;
     margin-top: 20px;
 }

 .calendar-day-cell {
     background: rgba(255, 255, 255, 0.03);
     border: 1px solid var(--glass-border);
     aspect-ratio: 1;
     padding: 8px;
     display: flex;
     flex-direction: column;
     justify-content: space-between;
 }

 .calendar-day-num {
     font-size: 10px;
     opacity: 0.5;
 }

 .calendar-shift-code {
     text-align: center;
 }

 .calendar-header-cell {
     text-align: center;
     font-size: 11px;
     font-weight: bold;
     color: var(--text-dim);
     padding-bottom: 8px;
 }

projects.js:
// --- LOGIC INTEGRATION (PROVIDED BY USER) ---
const LS_KEYS = { CONFIG: 'w5g_sys_cfg_v2', DATA: 'w5g_sys_data_v2', ACTIVE_MODULE: 'w5g_active_module', GROUPS: 'w5g_sys_groups_v2' };
const defaultGroupSettings = {
    D: { from: 0, label: 'D', cssVar: 'bg-d', colorDark: '#cc8a28', colorLight: '#d35400', icon: 'https://api.iconify.design/game-icons:rank-3.svg' },
    S: { from: 5, label: 'S', cssVar: 'bg-s', colorDark: '#0052cc', colorLight: '#0056b3', icon: 'https://api.iconify.design/game-icons:rank-2.svg' },
    L: { from: 10, label: 'L', cssVar: 'bg-l', colorDark: '#5981cc', colorLight: '#3178c6', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    K: { from: 12, label: 'K', cssVar: 'bg-k', colorDark: '#cc6f44', colorLight: '#c0392b', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    M: { from: 25, label: 'M', cssVar: 'bg-m', colorDark: '#cccc00', colorLight: '#b7950b', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    Y: { from: 37, label: 'Y', cssVar: 'bg-y', colorDark: '#00cc00', colorLight: '#196f3d', icon: 'https://api.iconify.design/game-icons:rank-1.svg' }
};

let DATA_MODULES = [];
let sys_config = { token: '', owner: 's-pro-v', repo: 'w5g.github.io', path: 'w5g-grudzien.json', branch: 'main' };
let sys_state = { data: null, sha: null, isLocked: true, currentDayIdx: 0, activeWorker: null, monthRanges: [] };
const SHIFT_MAP = { '1': 'DZIEN_06-18', '2': 'NOC_18-06', 'P1': 'PARKING_D1', 'P2': 'PARKING_D2', 'N1': 'NAGODZINY_N1', 'N2': 'NAGODZINY_N2', 'NP1': 'NAGODZINY_P1', 'NP2': 'NAGODZINY_P2', 'X': 'ABSENCJA_CRITICAL', 'U': 'URLOP_WYPEŁNIONY', 'S1': 'SZKOLENIE_TECH', 'S2': 'SZKOLENIE_TECH', 'ZW': 'ZWOLNIENIE_LEK', "W": "WOLNE_WEEKEND" };
const WEEKDAYS_MAP = { 'PN': 0, 'WT': 1, 'ŚR': 2, 'CZ': 3, 'PT': 4, 'SO': 5, 'ND': 6 };
const WEEKDAYS_HEADER = ['PN', 'WT', 'ŚR', 'CZ', 'PT', 'SO', 'ND'];
const VALID_SHIFT_CODES = Object.keys(SHIFT_MAP);

let groupSettings = { ...defaultGroupSettings };

function parseShiftCode(s) {
    s = (s || '').trim().toUpperCase();
    let base = s; let hours = null;
    const match = s.match(/^(.+?)\((\d+)\)$/);
    if (match) { base = match[1].trim(); hours = parseInt(match[2], 10); }
    return { base, hours };
}

function getHoursFromShift(s) {
    const { base } = parseShiftCode(s);
    if (['1', '2', 'P1', 'P2', 'N1', 'N2'].includes(base)) return 12;
    return 0;
}

async function init() {
    loadConfig();
    loadGroupSettings();
    await discoverDataStreams();
    const lastModule = localStorage.getItem(LS_KEYS.ACTIVE_MODULE);
    if (lastModule && DATA_MODULES.some(m => m.file === lastModule)) { sys_config.path = lastModule; }
    else if (DATA_MODULES.length > 0) { sys_config.path = DATA_MODULES[0].file; }
    loadCachedData();
    startClock();
    injectDataModuleSelector();
    updateFooter();
    if (sys_state.data) {
        identifyMonths();
        const today = new Date().getDate();
        const idx = sys_state.data.meta.days.findIndex(d => parseInt(d) === today);
        sys_state.currentDayIdx = idx !== -1 ? idx : 0;
        refreshUI();
    }
    document.getElementById('staff-search').addEventListener('input', (e) => renderStaffList(e.target.value));
    setupModalBackgroundHandlers();
    setLoader(false);
}

function loadGroupSettings() {
    const saved = localStorage.getItem(LS_KEYS.GROUPS);
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            Object.keys(defaultGroupSettings).forEach(key => {
                if (parsed[key]) groupSettings[key] = { ...defaultGroupSettings[key], ...parsed[key] };
            });
        } catch (e) { console.error(e); }
    }
    applyThemeSpecificColors();
}

function applyThemeSpecificColors() {
    const currentTheme = document.documentElement.getAttribute('data-theme') || 'dark';
    Object.values(groupSettings).forEach(g => {
        const color = currentTheme === 'light' ? g.colorLight : g.colorDark;
        if (color) document.documentElement.style.setProperty(`--${g.cssVar}`, color);
    });
}

function getWorkerGroup(id) {
    const pid = parseInt(id, 10); if (isNaN(pid)) return null;
    const sortedKeys = Object.keys(groupSettings).sort((a, b) => groupSettings[a].from - groupSettings[b].from);
    for (let i = 0; i < sortedKeys.length; i++) {
        const key = sortedKeys[i];
        const currentGrp = groupSettings[key];
        const nextKey = sortedKeys[i + 1];
        const nextFrom = nextKey ? groupSettings[nextKey].from : Infinity;
        if (pid >= currentGrp.from && pid < nextFrom) return { ...currentGrp, id: key };
    }
    return null;
}

async function discoverDataStreams() {
    const apiUrl = `https://api.github.com/repos/${sys_config.owner}/${sys_config.repo}/contents/`;
    try {
        const headers = { 'Accept': 'application/vnd.github.v3+json' };
        if (sys_config.token) headers['Authorization'] = `token ${sys_config.token}`;
        const res = await fetch(apiUrl, { headers });
        if (!res.ok) throw new Error();
        const files = await res.json();
        const cycleFiles = files.filter(f => f.name.startsWith('w5g-') && f.name.endsWith('.json') && f.name !== 'w5g.json');
        DATA_MODULES = cycleFiles.map(f => {
            const coreName = f.name.replace(/^w5g-|.json$/g, '').toUpperCase();
            return { id: coreName, label: coreName, file: f.name };
        });
    } catch (e) {
        DATA_MODULES = [{ id: 'OFFLINE', label: 'SYSTEM_OFFLINE', file: 'w5g-grudzien.json' }];
    }
}

function startClock() { setInterval(() => { document.getElementById('system-clock').textContent = new Date().toTimeString().split(' ')[0]; }, 1000); }

function injectDataModuleSelector() {
    const container = document.getElementById('data-module-container');
    const wrapper = document.createElement('div'); wrapper.className = 'custom-select';
    const trigger = document.createElement('div'); trigger.className = 'select-trigger';
    trigger.innerHTML = `<span id="selected-module-text">DATA_STREAM</span><i class="fas fa-chevron-down"></i>`;
    const options = document.createElement('div'); options.className = 'select-options';
    DATA_MODULES.forEach(mod => {
        const opt = document.createElement('div'); opt.className = 'option'; opt.innerHTML = `<i class="fas fa-database" style="margin-right:8px"></i>${mod.label}`;
        if (mod.file === sys_config.path) trigger.querySelector('#selected-module-text').textContent = mod.label;
        opt.onclick = () => switchDataModule(mod.file);
        options.appendChild(opt);
    });
    trigger.onclick = (e) => { e.stopPropagation(); options.classList.toggle('show'); };
    wrapper.appendChild(trigger); wrapper.appendChild(options);
    container.appendChild(wrapper);
}

async function switchDataModule(newPath) {
    sys_config.path = newPath; localStorage.setItem(LS_KEYS.ACTIVE_MODULE, newPath);
    await syncData('pull');
}

function identifyMonths() {
    if (!sys_state.data) return;
    const { days, months } = sys_state.data.meta;
    sys_state.monthRanges = [];
    let start = 0; let mIdx = 0;
    for (let i = 1; i < days.length; i++) {
        if (days[i] < days[i - 1]) {
            sys_state.monthRanges.push({ start, end: i - 1, name: (months?.[mIdx]) || `CYCLE_${mIdx + 1}` });
            start = i; mIdx++;
        }
    }
    sys_state.monthRanges.push({ start, end: days.length - 1, name: (months?.[mIdx]) || `CYCLE_${mIdx + 1}` });
}

function getCurrentMonthInfo() { return sys_state.monthRanges.find(m => sys_state.currentDayIdx >= m.start && sys_state.currentDayIdx <= m.end); }

async function syncData(mode) {
    if (!sys_config.token) return toggleModal('modal-config', true);
    setLoader(true);
    const url = `https://api.github.com/repos/${sys_config.owner}/${sys_config.repo}/contents/${sys_config.path}`;
    try {
        if (mode === 'pull') {
            const res = await fetch(`${url}?ref=${sys_config.branch}`, { headers: { 'Authorization': `token ${sys_config.token}` } });
            if (!res.ok) throw new Error("FETCH_ERR");
            const json = await res.json();
            const content = decodeURIComponent(atob(json.content).split('').map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2)).join(''));
            sys_state.sha = json.sha; sys_state.data = JSON.parse(content);
            localStorage.setItem(LS_KEYS.DATA, content);
            identifyMonths(); refreshUI(); notify("SYNC_SUCCESSFUL", "success");
        } else {
            const contentStr = JSON.stringify(sys_state.data, null, 2);
            const body = { message: `SYS_SYNC_${Date.now()}`, content: btoa(unescape(encodeURIComponent(contentStr))), branch: sys_config.branch };
            if (sys_state.sha) body.sha = sys_state.sha;
            const res = await fetch(url, { method: 'PUT', headers: { 'Authorization': `token ${sys_config.token}`, 'Content-Type': 'application/json' }, body: JSON.stringify(body) });
            if (!res.ok) throw new Error("PUSH_ERR");
            const result = await res.json(); sys_state.sha = result.content.sha;
            notify("REMOTE_STORAGE_UPDATED", "success");
        }
        updateFooter();
    } catch (err) { notify(`ERROR: ${err.message}`, "error"); }
    setLoader(false);
}

function refreshUI() {
    if (!sys_state.data) return;
    renderDashboard();
    renderScheduleTable();
    renderStaffList();
}

function renderDashboard() {
    if (!sys_state.data) return;
    const { meta, workers } = sys_state.data;
    const idx = sys_state.currentDayIdx;
    const curMonth = getCurrentMonthInfo();
    document.getElementById('day-counter').textContent = `DZIEŃ ROBOCZY [${idx + 1}/${meta.days.length}]`;
    document.getElementById('current-date-display').textContent = `${curMonth?.name || ''} ${meta.days[idx]} [${meta.weekdays[idx]}]`;

    const grouped = {};
    workers.forEach(w => {
        const rawCode = (w.shifts[idx] || '').trim().toUpperCase();
        if (!rawCode) return;
        const { base } = parseShiftCode(rawCode);
        let key = base;
        if (['1', 'N1', 'NP1', 'P1'].includes(base)) key = '1';
        else if (['2', 'N2', 'NP2', 'P2'].includes(base)) key = '2';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push({ worker: w, code: rawCode });
    });

    let html = '';
    Object.keys(grouped).sort().forEach(key => {
        let label = SHIFT_MAP[key] || `STATUS_${key}`;
        if (key === '1') label = "DZIEN_06-18 [+P1]";
        if (key === '2') label = "NOC_18-06 [+P2]";
        html += `
                    <div class="shift-card">
                        <div class="shift-header">
                            <span class="shift-tag ${getTagClass(key)}">${key}</span>
                            <span style="font-weight:700; font-size:12px;">${label}</span>
                            <span style="margin-left:auto; font-weight:800; color:var(--primary)">${grouped[key].length}</span>
                        </div>
                        <div class="shift-body">
                            ${grouped[key].map(item => {
            const grp = getWorkerGroup(item.worker.id);
            const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'var(--text-dim)';
            let subBadge = item.code !== key ? `<span class="sys-mini-badge ${getTagClass(item.code)}">${item.code}</span>` : '';
            let icon = grp?.icon ? `<div class="sys-icon-mask" style="--icon-url: url('${grp.icon}'); --icon-color: ${themeColor}; width: 18px; height: 18px; margin-right: 8px;"></div>` : '';
            return `<div class="worker-entry">${icon}<span>${item.worker.name}${subBadge}</span></div>`;
        }).join('')}
                        </div>
                    </div>`;
    });
    document.getElementById('shifts-grid').innerHTML = html || '<div style="opacity:0.3; padding:40px;">NO_ACTIVE_SHIFTS_DETECTED</div>';
    renderMiniCalendarSelect();
}

function renderMiniCalendarSelect() {
    const container = document.getElementById('mini-calendar');
    const { meta } = sys_state.data;
    container.innerHTML = `
                <div class="custom-select">
                    <div class="select-trigger" onclick="this.nextElementSibling.classList.toggle('show')">
                        <span>${meta.days[sys_state.currentDayIdx]} (${meta.weekdays[sys_state.currentDayIdx]})</span>
                        <i class="fas fa-calendar"></i>
                    </div>
                    <div class="select-options">
                        ${meta.days.map((d, i) => `<div class="option" onclick="jumpToDay(${i})">${d} (${meta.weekdays[i]})</div>`).join('')}
                    </div>
                </div>`;
}

function jumpToDay(idx) {
    sys_state.currentDayIdx = idx;
    renderDashboard();
}

function renderScheduleTable() {
    if (!sys_state.data) return;
    const { meta, workers } = sys_state.data;
    const locked = sys_state.isLocked ? 'disabled' : '';
    let html = `<thead><tr><th>ID</th><th style="text-align:left">OPERATOR</th>`;
    meta.days.forEach((d, i) => { html += `<th style="${meta.weekdays[i] === 'SO' || meta.weekdays[i] === 'ND' ? 'color:var(--primary)' : ''}">${d}<br>${meta.weekdays[i]}</th>`; });
    html += `<th>Σ</th></tr></thead><tbody>`;
    workers.forEach((w, wIdx) => {
        const grp = getWorkerGroup(w.id);
        const color = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : '';
        html += `<tr><td style="color:${color}; font-weight:700">${w.id}</td><td style="text-align:left; font-weight:600">${w.name}</td>`;
        w.shifts.forEach((s, dIdx) => {
            html += `<td><input type="text" class="cell-input ${getTagClass(s)}" value="${s}" ${locked} onchange="modifyShift(${wIdx}, ${dIdx}, this.value)"></td>`;
        });
        html += `<td>${w.shifts.reduce((a, b) => a + getHoursFromShift(b), 0)}H</td></tr>`;
    });
    document.getElementById('main-schedule-table').innerHTML = html + `</tbody>`;
}

function renderStaffList(filter = '') {
    const list = document.getElementById('staff-list');
    list.innerHTML = sys_state.data.workers
        .filter(w => w.name.toLowerCase().includes(filter.toLowerCase()))
        .map((w, idx) => {
            const grp = getWorkerGroup(w.id);
            const color = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'transparent';
            return `<div class="nav-item" style="border-left: 3px solid ${color}" onclick="viewStaffDetails(${idx})">
                        <div style="flex:1">
                            <div style="font-weight:700; color:var(--text-main)">${w.name}</div>
                            <div style="font-size:10px; font-family:var(--font-mono)">UID: ${w.id}</div>
                        </div>
                        <i class="fas fa-chevron-right" style="font-size:10px; opacity:0.3"></i>
                    </div>`;
        }).join('');
}

function viewStaffDetails(idx) {
    switchView('staff', document.querySelector('.nav-item'));
    const w = sys_state.data.workers[idx];
    const meta = sys_state.data.meta;
    const grp = getWorkerGroup(w.id);
    const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'var(--primary)';

    let gridHtml = '';
    WEEKDAYS_HEADER.forEach(d => gridHtml += `<div class="calendar-header-cell">${d}</div>`);
    const pad = WEEKDAYS_MAP[meta.weekdays[0]] || 0;
    for (let i = 0; i < pad; i++) gridHtml += `<div class="calendar-day-cell" style="opacity:0"></div>`;
    meta.days.forEach((d, i) => {
        const s = w.shifts[i];
        gridHtml += `
                    <div class="calendar-day-cell">
                        <span class="calendar-day-num">${d}</span>
                        <div class="calendar-shift-code"><span class="shift-tag ${getTagClass(s)}">${s || ''}</span></div>
                    </div>`;
    });

    document.getElementById('staff-details').innerHTML = `
                <div style="border-left: 8px solid ${themeColor}; padding-left: 20px; margin-bottom: 40px;">
                    <div style="font-family:var(--font-mono); color:${themeColor}; font-size:12px; font-weight:bold;">OPERATOR_IDENTIFIER: ${w.id}</div>
                    <h1 class="huge-title">${w.name}</h1>
                    <div style="margin-top:10px;"><span class="btn btn-active" style="border-color:${themeColor}; color:${themeColor}">GROUP: ${grp?.label || 'UNKNOWN'}</span></div>
                </div>
                <div class="calendar-grid">${gridHtml}</div>`;
}

function switchView(view, el) {
    document.querySelectorAll('.view-pane').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    document.getElementById(`view-${view}`).classList.add('active');
    if (el) el.classList.add('active');
}

function modifyShift(wIdx, dIdx, val) {
    sys_state.data.workers[wIdx].shifts[dIdx] = val.toUpperCase();
    localStorage.setItem(LS_KEYS.DATA, JSON.stringify(sys_state.data));
    renderDashboard();
}

function toggleSecurityLock() {
    sys_state.isLocked = !sys_state.isLocked;
    document.getElementById('btn-lock').innerHTML = sys_state.isLocked ? '<i class="fas fa-lock"></i> LOCK' : '<i class="fas fa-lock-open" style="color:var(--primary)"></i> UNLOCKED';
    renderScheduleTable();
    notify(sys_state.isLocked ? "ENCRYPTION_ACTIVE" : "WRITE_ACCESS_ENABLED", sys_state.isLocked ? "info" : "warning");
}

function toggleTheme() {
    const root = document.documentElement;
    const next = root.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
    root.setAttribute('data-theme', next);
    applyThemeSpecificColors(); refreshUI();
}

function notify(msg, type) {
    const el = document.getElementById('sys-notify');
    el.innerHTML = `<span style="color:var(--primary)">[SYS]</span> ${msg}`;
    el.classList.add('active');
    setTimeout(() => el.classList.remove('active'), 3000);
}

function setLoader(val) { document.getElementById('loader').style.display = val ? 'flex' : 'none'; }

function toggleModal(id, val) { document.getElementById(id).style.display = val ? 'flex' : 'none'; }

function saveConfiguration() {
    sys_config.token = document.getElementById('cfg-token').value;
    const repoParts = document.getElementById('cfg-repo').value.split('/');
    sys_config.owner = repoParts[0]; sys_config.repo = repoParts[1];
    localStorage.setItem(LS_KEYS.CONFIG, JSON.stringify(sys_config));
    toggleModal('modal-config', false);
    notify("UPLINK_CONFIG_SAVED", "success");
}

function loadConfig() {
    const saved = localStorage.getItem(LS_KEYS.CONFIG);
    if (saved) {
        sys_config = JSON.parse(saved);
        document.getElementById('cfg-token').value = sys_config.token;
        document.getElementById('cfg-repo').value = `${sys_config.owner}/${sys_config.repo}`;
    }
}

function loadCachedData() {
    const saved = localStorage.getItem(LS_KEYS.DATA);
    if (saved) sys_state.data = JSON.parse(saved);
}

function updateFooter() {
    document.getElementById('footer-path').textContent = sys_config.path;
    if (sys_state.sha) document.getElementById('footer-sha').textContent = sys_state.sha.substring(0, 8);
    document.getElementById('footer-sync').textContent = new Date().toLocaleTimeString();
}

function getTagClass(c) {
    const { base } = parseShiftCode(c || "");
    const code = base.toUpperCase();
    if (code === "1" || code.startsWith("N1") || code.startsWith("P1")) return "sb-1";
    if (code === "2" || code.startsWith("N2") || code.startsWith("P2")) return "sb-2";
    if (code === "X") return "sb-x";
    if (code === "U" || code === "ZW") return "sb-u";
    if (code.startsWith("S")) return "sb-s";
    return "";
}

function setupModalBackgroundHandlers() {
    window.onclick = function (event) { if (event.target.className === 'sys-overlay') event.target.style.display = 'none'; }
}

window.onload = init;

projects.css:
 :root {
     /* Palette: Matte Vellum Stacking */
     --bg-base: #0a0a0c;
     --vellum-bg: rgba(22, 22, 26, 0.7);
     --vellum-border: rgba(255, 255, 255, 0.08);
     --vellum-stack-1: rgba(30, 30, 35, 0.8);
     --vellum-stack-2: rgba(40, 40, 45, 0.9);

     --primary: #51a2ff;
     --primary-muted: rgba(81, 162, 255, 0.15);
     --accent: #ff4757;

     --text-main: #e1e1e6;
     --text-secondary: #9494a5;
     --text-badge: #ffffff;

     --status-success: #2ed573;
     --status-error: #ff4757;
     --status-warning: #ffa502;

     --font-ui: 'Inter', sans-serif;
     --font-data: 'JetBrains Mono', monospace;

     /* Group Overrides (Dynamic) */
     --bg-d: #cc8a28;
     --bg-s: #0052cc;
     --bg-l: #3178c6;
     --bg-k: #c0392b;
     --bg-m: #b7950b;
     --bg-y: #196f3d;

     --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
     --shadow-vellum: 0 8px 32px -4px rgba(0, 0, 0, 0.5);
     --shadow-stack: 0 4px 20px -2px rgba(0, 0, 0, 0.3);
 }

 [data-theme="light"] {
     --bg-base: #f0f2f5;
     --vellum-bg: rgba(255, 255, 255, 0.7);
     --vellum-border: rgba(0, 0, 0, 0.06);
     --vellum-stack-1: rgba(250, 250, 252, 0.8);
     --vellum-stack-2: rgba(245, 245, 248, 0.9);
     --text-main: #1a1a1e;
     --text-secondary: #636370;
     --shadow-vellum: 0 8px 32px -4px rgba(0, 0, 0, 0.1);
 }

 * {
     margin: 0;
     padding: 0;
     box-sizing: border-box;
     -webkit-font-smoothing: antialiased;
 }

 body {
     background-color: var(--bg-base);
     color: var(--text-main);
     font-family: var(--font-ui);
     height: 100vh;
     overflow: hidden;
     background-image:
         radial-gradient(circle at 20% 20%, rgba(81, 162, 255, 0.05) 0%, transparent 40%),
         radial-gradient(circle at 80% 80%, rgba(255, 71, 87, 0.03) 0%, transparent 40%);
 }

 /* Matte Texture Overlay */
 body::before {
     content: "";
     position: fixed;
     top: 0;
     left: 0;
     width: 100%;
     height: 100%;
     background-image: url("https://www.transparenttextures.com/patterns/asfalt-dark.png");
     opacity: 0.03;
     pointer-events: none;
     z-index: 9999;
 }

 /* Layout Structure */
 .app-container {
     display: grid;
     grid-template-columns: 80px 1fr;
     grid-template-rows: 70px 1fr 40px;
     height: 100vh;
     gap: 0;
 }

 /* Top Bar */
 .top-bar {
     grid-column: 2;
     display: flex;
     align-items: center;
     justify-content: space-between;
     padding: 0 30px;
     background: var(--vellum-bg);
     backdrop-filter: blur(15px);
     border-bottom: 1px solid var(--vellum-border);
     z-index: 100;
 }

 .sys-title {
     display: flex;
     align-items: center;
     gap: 15px;
     font-weight: 800;
     letter-spacing: -0.5px;
     font-size: 1.1rem;
 }

 .sys-title .logo {
     width: 32px;
     height: 32px;
     background: var(--primary);
     border-radius: 6px;
     display: flex;
     align-items: center;
     justify-content: center;
     color: #000;
     font-size: 14px;
     box-shadow: 0 4px 12px var(--primary-muted);
 }

 /* Sidebar Navigation */
 .sidebar {
     grid-row: 1 / 4;
     background: var(--vellum-stack-1);
     border-right: 1px solid var(--vellum-border);
     display: flex;
     flex-direction: column;
     align-items: center;
     padding: 20px 0;
     gap: 20px;
     z-index: 101;
 }

 .nav-item {
     width: 48px;
     height: 48px;
     border-radius: 12px;
     display: flex;
     align-items: center;
     justify-content: center;
     cursor: pointer;
     transition: var(--transition);
     color: var(--text-secondary);
     font-size: 18px;
     position: relative;
 }

 .nav-item:hover,
 .nav-item.active {
     color: var(--primary);
     background: var(--primary-muted);
 }

 .nav-item.active::after {
     content: "";
     position: absolute;
     left: -15px;
     width: 4px;
     height: 20px;
     background: var(--primary);
     border-radius: 0 4px 4px 0;
 }

 /* Main View Container */
 main {
     padding: 30px;
     overflow-y: auto;
     position: relative;
 }

 .view-pane {
     display: none;
     animation: paneEnter 0.6s cubic-bezier(0.16, 1, 0.3, 1) forwards;
 }

 .view-pane.active {
     display: block;
 }

 @keyframes paneEnter {
     from {
         opacity: 0;
         transform: translateY(10px) scale(0.99);
     }

     to {
         opacity: 1;
         transform: translateY(0) scale(1);
     }
 }

 /* Dashboard HUD */
 .hud-header {
     display: flex;
     justify-content: space-between;
     align-items: flex-end;
     margin-bottom: 30px;
 }

 .day-focus {
     display: flex;
     flex-direction: column;
     gap: 5px;
 }

 #day-counter {
     font-family: var(--font-data);
     font-size: 11px;
     color: var(--primary);
     font-weight: 700;
 }

 #current-date-display {
     font-size: 2.2rem;
     font-weight: 800;
     letter-spacing: -1px;
 }

 .hud-controls {
     display: flex;
     gap: 10px;
 }

 /* Shift Cards (The Stacking Effect) */
 .shifts-grid {
     display: grid;
     grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
     gap: 25px;
 }

 .shift-card {
     background: var(--vellum-bg);
     border: 1px solid var(--vellum-border);
     border-radius: 20px;
     padding: 24px;
     backdrop-filter: blur(10px);
     box-shadow: var(--shadow-vellum);
     transition: var(--transition);
     position: relative;
     overflow: hidden;
 }

 .shift-card::before {
     content: "";
     position: absolute;
     top: 0;
     left: 0;
     width: 100%;
     height: 4px;
     background: var(--primary-muted);
     opacity: 0.3;
 }

 .shift-card:hover {
     transform: translateY(-5px);
     border-color: rgba(81, 162, 255, 0.3);
 }

 .shift-header {
     display: flex;
     align-items: center;
     gap: 12px;
     margin-bottom: 20px;
     border-bottom: 1px solid var(--vellum-border);
     padding-bottom: 15px;
 }

 .shift-tag {
     padding: 4px 10px;
     border-radius: 6px;
     font-family: var(--font-data);
     font-weight: 700;
     font-size: 12px;
     text-transform: uppercase;
 }

 .shift-label {
     font-weight: 700;
     font-size: 13px;
     letter-spacing: 0.5px;
 }

 .shift-body {
     display: flex;
     flex-direction: column;
     gap: 12px;
 }

 .worker-entry {
     display: flex;
     align-items: center;
     padding: 10px 14px;
     background: var(--vellum-stack-1);
     border-radius: 10px;
     font-size: 14px;
     font-weight: 500;
     border: 1px solid transparent;
     transition: var(--transition);
 }

 .worker-entry:hover {
     background: var(--vellum-stack-2);
     border-color: var(--vellum-border);
     padding-left: 18px;
 }

 /* Table Aesthetics */
 .table-container {
     background: var(--vellum-bg);
     border-radius: 20px;
     border: 1px solid var(--vellum-border);
     overflow: auto;
     max-height: calc(100vh - 200px);
     box-shadow: var(--shadow-vellum);
 }

 table {
     width: 100%;
     border-collapse: separate;
     border-spacing: 0;
     font-family: var(--font-data);
     font-size: 12px;
 }

 th {
     position: sticky;
     top: 0;
     background: var(--vellum-stack-2);
     z-index: 10;
     padding: 15px 10px;
     text-align: center;
     font-weight: 800;
     border-bottom: 2px solid var(--vellum-border);
     color: var(--text-secondary);
 }

 td {
     padding: 8px;
     text-align: center;
     border-bottom: 1px solid var(--vellum-border);
     border-right: 1px solid var(--vellum-border);
 }

 .cell-input {
     width: 100%;
     border: none;
     background: transparent;
     color: inherit;
     text-align: center;
     font-family: inherit;
     font-size: inherit;
     padding: 4px;
     border-radius: 4px;
 }

 .cell-input:focus {
     background: var(--primary-muted);
     outline: 2px solid var(--primary);
 }

 /* Specific Cell Colors */
 .cell-1 {
     background: rgba(204, 138, 40, 0.1);
     color: #cc8a28;
 }

 .cell-2 {
     background: rgba(0, 82, 204, 0.1);
     color: #4b92ff;
 }

 .cell-x {
     background: rgba(255, 71, 87, 0.1);
     color: #ff4757;
 }

 .cell-u {
     background: rgba(46, 213, 115, 0.1);
     color: #2ed573;
 }

 /* Vellum Specific Modals */
 .sys-overlay {
     position: fixed;
     inset: 0;
     background: rgba(0, 0, 0, 0.8);
     backdrop-filter: blur(8px);
     display: none;
     align-items: center;
     justify-content: center;
     z-index: 1000;
 }

 .sys-modal {
     background: var(--vellum-stack-2);
     width: 90%;
     max-width: 600px;
     border-radius: 24px;
     border: 1px solid var(--vellum-border);
     box-shadow: 0 30px 60px -12px rgba(0, 0, 0, 0.5);
     overflow: hidden;
     animation: modalScale 0.4s cubic-bezier(0.16, 1, 0.3, 1);
 }

 @keyframes modalScale {
     from {
         transform: scale(0.9) translateY(20px);
         opacity: 0;
     }

     to {
         transform: scale(1) translateY(0);
         opacity: 1;
     }
 }

 .sys-modal-header {
     padding: 25px 30px;
     border-bottom: 1px solid var(--vellum-border);
     display: flex;
     justify-content: space-between;
     align-items: center;
     font-weight: 800;
     letter-spacing: 1px;
     font-size: 0.9rem;
 }

 .sys-modal-body {
     padding: 30px;
 }

 /* Buttons: Matte Material */
 .btn {
     background: var(--vellum-stack-1);
     border: 1px solid var(--vellum-border);
     color: var(--text-main);
     padding: 10px 18px;
     border-radius: 10px;
     cursor: pointer;
     font-weight: 600;
     font-size: 13px;
     display: inline-flex;
     align-items: center;
     gap: 8px;
     transition: var(--transition);
 }

 .btn:hover {
     background: var(--vellum-stack-2);
     border-color: var(--primary);
     transform: translateY(-2px);
 }

 .btn-active {
     background: var(--primary);
     color: #000;
     border-color: var(--primary);
 }

 .btn-theme {
     font-size: 1.2rem;
     color: var(--text-secondary);
     cursor: pointer;
     transition: var(--transition);
 }

 /* SVG Masking Engine */
 .sys-icon-mask {
     background-color: currentColor;
     -webkit-mask-image: var(--icon-url);
     mask-image: var(--icon-url);
     -webkit-mask-repeat: no-repeat;
     mask-repeat: no-repeat;
     -webkit-mask-size: contain;
     mask-size: contain;
     display: inline-block;
     background: var(--icon-color);
 }

 /* Footer */
 .footer {
     grid-column: 2;
     background: var(--vellum-bg);
     border-top: 1px solid var(--vellum-border);
     padding: 0 30px;
     display: flex;
     align-items: center;
     justify-content: space-between;
     font-size: 10px;
     font-family: var(--font-data);
     color: var(--text-secondary);
 }

 .status-pill {
     display: flex;
     align-items: center;
     gap: 6px;
 }

 .status-dot {
     width: 6px;
     height: 6px;
     background: var(--status-success);
     border-radius: 50%;
     box-shadow: 0 0 10px var(--status-success);
 }

 /* Custom Dropdown (Vellum Style) */
 .custom-select {
     position: relative;
     min-width: 180px;
 }

 .select-trigger {
     background: var(--vellum-stack-1);
     border: 1px solid var(--vellum-border);
     padding: 8px 15px;
     border-radius: 10px;
     cursor: pointer;
     display: flex;
     align-items: center;
     justify-content: space-between;
     font-size: 13px;
     font-weight: 600;
 }

 .select-options {
     position: absolute;
     top: calc(100% + 10px);
     left: 0;
     width: 100%;
     background: var(--vellum-stack-2);
     border: 1px solid var(--vellum-border);
     border-radius: 12px;
     box-shadow: var(--shadow-vellum);
     display: none;
     overflow: hidden;
     z-index: 200;
 }

 .select-options.show {
     display: block;
 }

 .option {
     padding: 10px 15px;
     cursor: pointer;
     transition: var(--transition);
     font-size: 13px;
 }

 .option:hover {
     background: var(--primary-muted);
     color: var(--primary);
 }

 /* Mini Badges */
 .sys-mini-badge {
     font-size: 9px;
     padding: 1px 5px;
     border-radius: 4px;
     margin-left: 6px;
     background: var(--vellum-border);
     vertical-align: middle;
 }

 .sb-1 {
     background: rgba(204, 138, 40, 0.2);
     color: #cc8a28;
     border: 1px solid rgba(204, 138, 40, 0.3);
 }

 .sb-2 {
     background: rgba(0, 82, 204, 0.2);
     color: #4b92ff;
     border: 1px solid rgba(0, 82, 204, 0.3);
 }

 .sb-p {
     background: rgba(183, 149, 11, 0.2);
     color: #b7950b;
     border: 1px solid rgba(183, 149, 11, 0.3);
 }

 .sb-x {
     background: rgba(255, 71, 87, 0.2);
     color: #ff4757;
     border: 1px solid rgba(255, 71, 87, 0.3);
 }

 /* Loader */
 #loader {
     position: fixed;
     inset: 0;
     background: rgba(10, 10, 12, 0.9);
     display: none;
     flex-direction: column;
     align-items: center;
     justify-content: center;
     z-index: 9999;
 }

 .scanner-bar {
     width: 200px;
     height: 2px;
     background: var(--vellum-border);
     position: relative;
     overflow: hidden;
     margin-top: 20px;
 }

 .scanner-bar::after {
     content: "";
     position: absolute;
     left: -100%;
     width: 100%;
     height: 100%;
     background: var(--primary);
     animation: scanning 1.5s infinite linear;
 }

 @keyframes scanning {
     0% {
         left: -100%;
     }

     100% {
         left: 100%;
     }
 }

 /* Responsive */
 @media (max-width: 1024px) {
     .app-container {
         grid-template-columns: 1fr;
         grid-template-rows: 70px 60px 1fr 40px;
     }

     .sidebar {
         grid-row: 2;
         flex-direction: row;
         width: 100%;
         height: 60px;
         padding: 0 20px;
         border-right: none;
         border-bottom: 1px solid var(--vellum-border);
     }

     .nav-item.active::after {
         bottom: -15px;
         left: 50%;
         width: 20px;
         height: 4px;
         transform: translateX(-50%);
     }

     .top-bar {
         grid-column: 1;
     }

     main {
         grid-column: 1;
     }

     .footer {
         grid-column: 1;
     }
 }

