// --- CONSTANTS & STATE ---
const LS_KEYS = { CONFIG: 'w5g_sys_cfg_v2', DATA: 'w5g_sys_data_v2', ACTIVE_MODULE: 'w5g_active_module', GROUPS: 'w5g_sys_groups_v2' };

const defaultGroupSettings = {
    D: { from: 0, label: 'D', cssVar: 'bg-d', colorDark: '#cc8a28', colorLight: '#d35400', icon: 'https://api.iconify.design/game-icons:rank-3.svg' },
    S: { from: 5, label: 'S', cssVar: 'bg-s', colorDark: '#0052cc', colorLight: '#0056b3', icon: 'https://api.iconify.design/game-icons:rank-2.svg' },
    L: { from: 10, label: 'L', cssVar: 'bg-l', colorDark: '#5981cc', colorLight: '#3178c6', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    K: { from: 12, label: 'K', cssVar: 'bg-k', colorDark: '#cc6f44', colorLight: '#c0392b', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    M: { from: 25, label: 'M', cssVar: 'bg-m', colorDark: '#cccc00', colorLight: '#b7950b', icon: 'https://api.iconify.design/game-icons:rank-1.svg' },
    Y: { from: 37, label: 'Y', cssVar: 'bg-y', colorDark: '#00cc00', colorLight: '#196f3d', icon: 'https://api.iconify.design/game-icons:rank-1.svg' }
};

let DATA_MODULES = [];
let sys_config = { token: '', owner: 's-pro-v', repo: 'w5g.github.io', path: 'w5g-grudzien.json', branch: 'main' };
let sys_state = { data: null, sha: null, isLocked: true, currentDayIdx: 0, activeWorker: null, monthRanges: [] };

const SHIFT_MAP = {
    '1': 'DZIEN_06-18', '2': 'NOC_18-06', 'P1': 'PARKING_D1', 'P2': 'PARKING_D2',
    'N1': 'NAGODZINY_N1', 'N2': 'NAGODZINY_N2', 'NP1': 'NAGODZINY_P1', 'NP2': 'NAGODZINY_P2',
    'X': 'ABSENCJA_CRITICAL', 'U': 'URLOP_WYPEŁNIONY', 'S1': 'SZKOLENIE_TECH', 'S2': 'SZKOLENIE_TECH',
    'ZW': 'ZWOLNIENIE_LEK', "W": "WOLNE_WEEKEND"
};

const WEEKDAYS_MAP = { 'PN': 0, 'WT': 1, 'ŚR': 2, 'CZ': 3, 'PT': 4, 'SO': 5, 'ND': 6 };
const WEEKDAYS_HEADER = ['PN', 'WT', 'ŚR', 'CZ', 'PT', 'SO', 'ND'];
const VALID_SHIFT_CODES = Object.keys(SHIFT_MAP);

function parseShiftCode(s) {
    s = (s || '').trim().toUpperCase();
    let base = s; let hours = null;
    const match = s.match(/^(.+?)\((\d+)\)$/);
    if (match) { base = match[1].trim(); hours = parseInt(match[2], 10); }
    return { base, hours };
}

function getHoursFromShift(s) {
    const { base } = parseShiftCode(s);
    if (['1', '2', 'P1', 'P2', 'N1', 'N2'].includes(base)) return 12;
    return 0;
}

// --- CORE FUNCTIONS ---
async function init() {
    loadConfig();
    loadGroupSettings();
    await discoverDataStreams();

    const lastModule = localStorage.getItem(LS_KEYS.ACTIVE_MODULE);
    if (lastModule && DATA_MODULES.some(m => m.file === lastModule)) {
        sys_config.path = lastModule;
    } else if (DATA_MODULES.length > 0) {
        sys_config.path = DATA_MODULES[0].file;
    }

    loadCachedData();
    startClock();
    injectDataModuleSelector();
    updateFooter();

    if (sys_state.data) {
        identifyMonths();
        const today = new Date().getDate();
        const idx = sys_state.data.meta.days.findIndex(d => parseInt(d) === today);
        sys_state.currentDayIdx = idx !== -1 ? idx : 0;
        refreshUI();
    } else {
        syncData('pull');
    }

    document.getElementById('staff-search').addEventListener('input', (e) => renderStaffList(e.target.value));
    setupModalBackgroundHandlers();
}

let groupSettings = { ...defaultGroupSettings };
function loadGroupSettings() {
    const saved = localStorage.getItem(LS_KEYS.GROUPS);
    if (saved) {
        try {
            const parsed = JSON.parse(saved);
            Object.keys(defaultGroupSettings).forEach(key => {
                if (parsed[key]) {
                    groupSettings[key] = { ...defaultGroupSettings[key], ...parsed[key] };
                }
            });
        } catch (e) { console.error("GROUP_CONFIG_LOAD_FAIL", e); }
    }
    applyThemeSpecificColors();
}

function applyThemeSpecificColors() {
    const currentTheme = document.documentElement.getAttribute('data-theme') || 'dark';
    Object.values(groupSettings).forEach(g => {
        const color = currentTheme === 'light' ? g.colorLight : g.colorDark;
        if (color) {
            document.documentElement.style.setProperty(`--${g.cssVar}`, color);
        }
    });
}

function getWorkerGroup(id) {
    const pid = parseInt(id, 10);
    if (isNaN(pid)) return null;
    const sortedKeys = Object.keys(groupSettings).sort((a, b) => groupSettings[a].from - groupSettings[b].from);
    for (let i = 0; i < sortedKeys.length; i++) {
        const key = sortedKeys[i];
        const currentGrp = groupSettings[key];
        const nextKey = sortedKeys[i + 1];
        const nextFrom = nextKey ? groupSettings[nextKey].from : Infinity;
        if (pid >= currentGrp.from && pid < nextFrom) return { ...currentGrp, id: key };
    }
    return null;
}

async function discoverDataStreams() {
    const apiUrl = `https://api.github.com/repos/${sys_config.owner}/${sys_config.repo}/contents/`;
    try {
        const headers = { 'Accept': 'application/vnd.github.v3+json' };
        if (sys_config.token) headers['Authorization'] = `token ${sys_config.token}`;
        const res = await fetch(apiUrl, { headers });
        if (!res.ok) throw new Error("REPO_FAIL");
        const files = await res.json();
        const cycleFiles = files.filter(f => f.name.startsWith('w5g-') && f.name.endsWith('.json') && f.name !== 'w5g.json');
        DATA_MODULES = cycleFiles.map(f => {
            const coreName = f.name.replace(/^w5g-|.json$/g, '').toUpperCase();
            return { id: coreName, label: coreName, file: f.name };
        }).sort((a, b) => a.id.localeCompare(b.id));
    } catch (e) {
        DATA_MODULES = [{ id: 'OFFLINE', label: 'OFFLINE_MODE', file: 'w5g-grudzien.json' }];
    }
}

function startClock() {
    setInterval(() => {
        const now = new Date();
        document.getElementById('system-clock').textContent = now.toTimeString().split(' ')[0];
    }, 1000);
}

function injectDataModuleSelector() {
    const container = document.querySelector('.top-bar-right');
    const wrapper = document.createElement('div');
    wrapper.className = 'custom-select';
    wrapper.innerHTML = `
                <div class="select-trigger"><span id="selected-module-text">SELECT_STREAM</span><i class="fas fa-chevron-down"></i></div>
                <div class="select-options"></div>
            `;
    const optionsContainer = wrapper.querySelector('.select-options');
    DATA_MODULES.forEach(mod => {
        const option = document.createElement('div');
        option.className = 'option';
        option.innerHTML = `<i class="fas fa-database" style="margin-right:10px; opacity:0.5;"></i> ${mod.label}`;
        if (mod.file === sys_config.path) wrapper.querySelector('#selected-module-text').textContent = mod.label;
        option.addEventListener('click', () => switchDataModule(mod.file));
        optionsContainer.appendChild(option);
    });
    wrapper.querySelector('.select-trigger').addEventListener('click', (e) => {
        e.stopPropagation();
        optionsContainer.classList.toggle('show');
    });
    document.addEventListener('click', () => optionsContainer.classList.remove('show'));
    container.insertBefore(wrapper, container.firstChild);
}

async function switchDataModule(newPath) {
    if (newPath === sys_config.path) return;
    notify(`MOUNTING_STREAM: ${newPath}`, "info");
    sys_config.path = newPath;
    localStorage.setItem(LS_KEYS.ACTIVE_MODULE, newPath);
    await syncData('pull');
    location.reload(); // Quick reset for UI state
}

function updateFooter() {
    if (sys_state.sha) document.getElementById('footer-sha').textContent = sys_state.sha.substring(0, 7);
    if (sys_config.path) document.getElementById('footer-path').textContent = sys_config.path;
    document.getElementById('footer-sync').textContent = new Date().toLocaleTimeString();
}

function identifyMonths() {
    if (!sys_state.data) return;
    const { days, months } = sys_state.data.meta;
    sys_state.monthRanges = [];
    let rangeStart = 0;
    let monthIdx = 0;
    for (let i = 1; i < days.length; i++) {
        if (days[i] < days[i - 1]) {
            sys_state.monthRanges.push({ start: rangeStart, end: i - 1, name: months ? months[monthIdx] : 'MONTH' });
            rangeStart = i; monthIdx++;
        }
    }
    sys_state.monthRanges.push({ start: rangeStart, end: days.length - 1, name: months ? months[monthIdx] : 'MONTH' });
}

function stepDay(delta) {
    if (!sys_state.data) return;
    const newIdx = sys_state.currentDayIdx + delta;
    if (newIdx >= 0 && newIdx < sys_state.data.meta.days.length) {
        sys_state.currentDayIdx = newIdx;
        renderDashboard();
    }
}

function stepMonth(delta) {
    if (!sys_state.data) return;
    const curIdx = sys_state.currentDayIdx;
    const mRangeIdx = sys_state.monthRanges.findIndex(m => curIdx >= m.start && curIdx <= m.end);
    const nextIdx = mRangeIdx + delta;
    if (nextIdx >= 0 && nextIdx < sys_state.monthRanges.length) {
        sys_state.currentDayIdx = sys_state.monthRanges[nextIdx].start;
        renderDashboard();
        renderScheduleTable();
    }
}

async function syncData(mode) {
    if (!sys_config.token) return toggleModal('modal-config', true);
    setLoader(true);
    const url = `https://api.github.com/repos/${sys_config.owner}/${sys_config.repo}/contents/${sys_config.path}`;
    try {
        if (mode === 'pull') {
            const res = await fetch(`${url}?ref=${sys_config.branch}`, {
                headers: { 'Authorization': `token ${sys_config.token}`, 'Accept': 'application/vnd.github.v3+json' }
            });
            if (!res.ok) throw new Error("PULL_FAIL");
            const json = await res.json();
            const content = decodeURIComponent(atob(json.content).split('').map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2)).join(''));
            sys_state.sha = json.sha;
            sys_state.data = JSON.parse(content);
            identifyMonths();
            notify("DATA_SYNC_SUCCESS", "success");
            refreshUI();
        } else {
            const contentStr = JSON.stringify(sys_state.data, null, 2);
            const encoded = btoa(unescape(encodeURIComponent(contentStr)));
            const body = { message: `SYS_SYNC_${Date.now()}`, content: encoded, branch: sys_config.branch, sha: sys_state.sha };
            const res = await fetch(url, {
                method: 'PUT', headers: { 'Authorization': `token ${sys_config.token}`, 'Content-Type': 'application/json' },
                body: JSON.stringify(body)
            });
            if (!res.ok) throw new Error("PUSH_FAIL");
            const result = await res.json();
            sys_state.sha = result.content.sha;
            notify("REMOTE_STORAGE_UPDATED", "success");
        }
    } catch (err) { notify(`SYNC_ERROR: ${err.message}`, "error"); }
    finally { setLoader(false); updateFooter(); }
}

function refreshUI() {
    if (!sys_state.data) return;
    renderDashboard();
    renderScheduleTable();
    renderStaffList();
}

function renderDashboard() {
    if (!sys_state.data) return;
    const { meta, workers } = sys_state.data;
    const idx = sys_state.currentDayIdx;
    const weekday = meta.weekdays[idx];
    const dayNum = meta.days[idx];

    document.getElementById('day-counter').textContent = `WORK_DAY [${idx + 1}/${meta.days.length}]`;
    document.getElementById('current-date-display').textContent = `${dayNum} ${weekday}`;

    const dayCodes = ['1', 'N1', 'NP1', 'P1'];
    const nightCodes = ['2', 'N2', 'NP2', 'P2'];
    const grouped = {};

    workers.forEach(w => {
        const rawCode = (w.shifts[idx] || '').trim().toUpperCase();
        if (!rawCode) return;
        const { base } = parseShiftCode(rawCode);
        let cardKey = base;
        if (dayCodes.includes(base)) cardKey = '1';
        else if (nightCodes.includes(base)) cardKey = '2';
        if (!grouped[cardKey]) grouped[cardKey] = [];
        grouped[cardKey].push({ worker: w, code: rawCode });
    });

    let html = '';
    Object.keys(grouped).sort().forEach(key => {
        const badgeClass = getTagClass(key);
        let label = SHIFT_MAP[key] || `STATUS_${key}`;
        if (key === '1') label = "DZIEN_06-18 [+P1]";
        if (key === '2') label = "NOC_18-06 [+P2]";

        html += `
                    <div class="shift-card">
                        <div class="shift-header">
                            <span class="shift-tag ${badgeClass}">${key}</span>
                            <span class="shift-label">${label}</span>
                            <span style="margin-left:auto; font-weight:800; color:var(--primary);">${grouped[key].length}</span>
                        </div>
                        <div class="shift-body">
                            ${grouped[key].map(item => {
            const grp = getWorkerGroup(item.worker.id);
            const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'var(--text-secondary)';
            const iconHtml = grp?.icon ? `<div class="sys-icon-mask" style="--icon-url: url('${grp.icon}'); --icon-color: ${themeColor}; width:18px; height:18px; margin-right:10px;"></div>` : '';
            return `
                                    <div class="worker-entry">
                                        ${iconHtml}
                                        <span>${item.worker.name}</span>
                                        ${item.code !== key ? `<span class="sys-mini-badge ${getTagClass(item.code)}">${item.code}</span>` : ''}
                                    </div>
                                `;
        }).join('')}
                        </div>
                    </div>
                `;
    });
    document.getElementById('shifts-grid').innerHTML = html || '<div style="opacity:0.2; padding:40px; text-align:center; width:100%;">NO_ACTIVE_SHIFTS_RECORDED</div>';
}

function renderScheduleTable() {
    if (!sys_state.data) return;
    const { meta, workers } = sys_state.data;
    const locked = sys_state.isLocked ? 'disabled' : '';

    let html = `<thead><tr><th style="width:50px;">ID</th><th style="text-align:left; width:200px;">OPERATOR</th>`;
    meta.days.forEach((d, i) => {
        const weekend = meta.weekdays[i] === 'SO' || meta.weekdays[i] === 'ND';
        html += `<th style="${weekend ? 'background:var(--primary-muted);' : ''}">${d}<br><small>${meta.weekdays[i]}</small></th>`;
    });
    html += `<th>SUMA</th></tr></thead><tbody>`;

    workers.forEach((w, wIdx) => {
        let hrs = 0;
        const grp = getWorkerGroup(w.id);
        const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'inherit';

        html += `<tr>
                    <td style="color:${themeColor}; font-weight:800;">${w.id}</td>
                    <td style="text-align:left; font-weight:700; border-left:4px solid ${themeColor}; padding-left:12px;">${w.name}</td>`;
        w.shifts.forEach((s, dIdx) => {
            hrs += getHoursFromShift(s);
            const cellClass = getCellClass(s);
            html += `<td class="${cellClass}"><input type="text" class="cell-input" value="${s}" ${locked} onchange="modifyShift(${wIdx}, ${dIdx}, this.value)"></td>`;
        });
        html += `<td style="font-weight:800; background:var(--vellum-stack-1);">${hrs}H</td></tr>`;
    });

    document.getElementById('main-schedule-table').innerHTML = html + `</tbody>`;
}

function renderStaffList(filter = '') {
    if (!sys_state.data) return;
    const list = document.getElementById('staff-list');
    list.innerHTML = sys_state.data.workers
        .filter(w => w.name.toLowerCase().includes(filter.toLowerCase()))
        .map((w, idx) => {
            const grp = getWorkerGroup(w.id);
            const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'transparent';
            return `<div class="worker-entry" style="cursor:pointer; border-left:3px solid ${themeColor};" onclick="viewStaffDetails(${idx})">
                        <div style="flex:1">
                            <div style="font-weight:700;">${w.name}</div>
                            <div style="font-size:10px; opacity:0.5;">UID: ${w.id}</div>
                        </div>
                        <i class="fas fa-chevron-right" style="opacity:0.3; font-size:10px;"></i>
                    </div>`;
        }).join('');
}

function viewStaffDetails(idx) {
    const w = sys_state.data.workers[idx];
    const meta = sys_state.data.meta;
    const grp = getWorkerGroup(w.id);
    const themeColor = grp ? (document.documentElement.getAttribute('data-theme') === 'light' ? grp.colorLight : grp.colorDark) : 'var(--primary)';

    let totalHrs = 0;
    w.shifts.forEach(s => totalHrs += getHoursFromShift(s));

    document.getElementById('staff-details').innerHTML = `
                <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:40px;">
                    <div>
                        <div style="background:${themeColor}; color:white; display:inline-block; padding:4px 12px; border-radius:4px; font-weight:800; font-size:10px; margin-bottom:15px;">GROUP_${grp?.label || 'NONE'}</div>
                        <h1 style="font-size:2.5rem; letter-spacing:-1.5px;">${w.name}</h1>
                        <p style="font-family:var(--font-data); opacity:0.5;">IDENTIFIER: ${w.id}</p>
                    </div>
                    <div style="background:var(--vellum-stack-1); padding:20px; border-radius:15px; text-align:right;">
                        <div style="font-size:10px; font-weight:800; opacity:0.5;">TOTAL_DUTY_HOURS</div>
                        <div style="font-size:2rem; font-weight:800; color:var(--primary);">${totalHrs}H</div>
                    </div>
                </div>
                <div style="display:grid; grid-template-columns: repeat(7, 1fr); gap:10px;">
                    ${WEEKDAYS_HEADER.map(h => `<div style="text-align:center; font-size:10px; font-weight:800; opacity:0.3; padding-bottom:10px;">${h}</div>`).join('')}
                    ${Array(WEEKDAYS_MAP[meta.weekdays[0]] || 0).fill(0).map(() => `<div style="height:60px; opacity:0.1; background:var(--vellum-stack-1); border-radius:8px;"></div>`).join('')}
                    ${w.shifts.map((s, i) => `
                        <div style="height:60px; background:var(--vellum-stack-1); border-radius:8px; display:flex; flex-direction:column; align-items:center; justify-content:center; position:relative; border:1px solid var(--vellum-border);">
                            <span style="position:absolute; top:4px; left:6px; font-size:9px; opacity:0.3;">${meta.days[i]}</span>
                            <span class="shift-tag ${getTagClass(s)}" style="font-size:10px;">${s || '-'}</span>
                        </div>
                    `).join('')}
                </div>
            `;
}

window.modifyShift = (wIdx, dIdx, val) => {
    sys_state.data.workers[wIdx].shifts[dIdx] = val.toUpperCase();
    refreshUI();
};

function switchView(view, el) {
    document.querySelectorAll('.view-pane').forEach(p => p.classList.remove('active'));
    document.querySelectorAll('.nav-item').forEach(l => l.classList.remove('active'));
    document.getElementById(`view-${view}`).classList.add('active');
    el.classList.add('active');
    document.getElementById('current-view-name').textContent = `${view.toUpperCase()}_HUD`;
}

function toggleSecurityLock() {
    sys_state.isLocked = !sys_state.isLocked;
    const btn = document.getElementById('btn-lock');
    btn.innerHTML = sys_state.isLocked ? '<i class="fas fa-lock"></i> READ_ONLY' : '<i class="fas fa-lock-open"></i> EDIT_MODE';
    btn.classList.toggle('btn-active', !sys_state.isLocked);
    renderScheduleTable();
    notify(sys_state.isLocked ? "ACCESS_RESTRICTED" : "WRITE_ACCESS_GRANTED", "info");
}

function toggleTheme() {
    const root = document.documentElement;
    const current = root.getAttribute('data-theme');
    const next = current === 'dark' ? 'light' : 'dark';
    root.setAttribute('data-theme', next);
    document.querySelector('.btn-theme i').className = next === 'dark' ? 'fas fa-sun' : 'fas fa-moon';
    applyThemeSpecificColors();
    refreshUI();
}

function notify(msg, type) {
    const el = document.getElementById('sys-notify');
    el.textContent = `> ${msg}`;
    el.style.borderLeftColor = type === 'error' ? 'var(--status-error)' : 'var(--primary)';
    el.style.transform = 'translateX(0)';
    setTimeout(() => el.style.transform = 'translateX(120%)', 3000);
}

function toggleModal(id, val) {
    document.getElementById(id).style.display = val ? 'flex' : 'none';
}

function setLoader(val) { document.getElementById('loader').style.display = val ? 'flex' : 'none'; }

function saveConfiguration() {
    sys_config.token = document.getElementById('cfg-token').value;
    const repoParts = document.getElementById('cfg-repo').value.split('/');
    if (repoParts.length === 2) { sys_config.owner = repoParts[0]; sys_config.repo = repoParts[1]; }
    localStorage.setItem(LS_KEYS.CONFIG, JSON.stringify(sys_config));
    toggleModal('modal-config', false);
    syncData('pull');
}

function loadConfig() {
    const saved = localStorage.getItem(LS_KEYS.CONFIG);
    if (saved) {
        sys_config = JSON.parse(saved);
        document.getElementById('cfg-token').value = sys_config.token;
        document.getElementById('cfg-repo').value = `${sys_config.owner}/${sys_config.repo}`;
    }
}

function loadCachedData() {
    const saved = localStorage.getItem(LS_KEYS.DATA);
    if (saved) sys_state.data = JSON.parse(saved);
}

function setupModalBackgroundHandlers() {
    document.addEventListener('click', (e) => {
        if (e.target.classList.contains('sys-overlay')) toggleModal(e.target.id, false);
    });
}

function getTagClass(c) {
    const { base } = parseShiftCode(c || "");
    if (base === "1") return "sb-1";
    if (base === "2") return "sb-2";
    if (base.startsWith("P")) return "sb-p";
    if (base === "X") return "sb-x";
    return "";
}

function getCellClass(c) {
    const { base } = parseShiftCode(c || "");
    if (base === "1") return "cell-1";
    if (base === "2") return "cell-2";
    if (base === "X") return "cell-x";
    if (base === "U") return "cell-u";
    return "";
}

window.onload = init;

