    function unmask(encoded, key) {
        return xor(base64Decode(encoded), key);
    }

    // --- Opcjonalnie: tylko XOR (bez Base64), gdy wynik ma być czytelny w pliku ---
    function xorEncrypt(str, key) {
        return xor(str, key);
    }

    function xorDecrypt(str, key) {
        return xor(str, key);
    }

