// --- CONFIG & STATE ---
const GITHUB_USER = 's-pro-v';
const GITHUB_REPO = 'json-lista';
const GITHUB_FILE = 'mobile-w.json';
const STORAGE_KEY = 'nexus_schedule_data';

const TWELVE_HOUR_CODES = new Set(["1", "2", "P1", "P2", "N1", "N2", "NP1", "NP2"]);
const DAY_SHIFT_CODES = new Set(["1", "P1"]);
const NIGHT_SHIFT_CODES = new Set(["2", "22", "P2", "N1", "N2", "NP1", "NP2"]);

// Basic default data to prevent completely empty states if no local storage
const DEFAULT_JSON = {
    "meta": {
        "generated": new Date().toISOString(),
        "daysCount": 30,
        "days": Array.from({ length: 30 }, (_, i) => String(i + 1)),
        "weekdays": ["SO", "ND", "PN", "WT", "SR", "CZ", "PT", "SO", "ND", "PN", "WT", "SR", "CZ", "PT", "SO", "ND", "PN", "WT", "SR", "CZ", "PT", "SO", "ND", "PN", "WT", "SR", "CZ", "PT", "SO", "ND"]
    },
    "workers": [
        { "id": 1, "name": "Przykład (Offline)", "shifts": ["1", "1", "2", "", "", "2", "", "1", "1", "2", "", "", "2", "", "1", "1", "", "", "", "2", "", "N2", "N2", "", "", "", "2", "", "", ""] }
    ]
};

let state = {
    content: "",
    parsed: null,
    isValid: true,
    selectedWorkerIndices: new Set(),
    baseline: null,
    highlightWhoOnShift: false,
    currentView: 'schedule'
};

// --- UTILS ---
const deepCopy = (obj) => JSON.parse(JSON.stringify(obj));

function calculateHours(shifts, limit = null) {
    if (!shifts) return 0;
    const target = limit ? shifts.slice(0, limit) : shifts;
    let count = 0;
    target.forEach(s => {
        let code = String(s || "").trim().toUpperCase().replace(/\(8\)\s*$/i, '');
        if (TWELVE_HOUR_CODES.has(code)) count++;
    });
    return count * 12;
}

function getTodayColumnIndex() {
    if (!state.parsed || !state.parsed.meta || !state.parsed.meta.days) return -1;
    const todayStr = String(new Date().getDate());
    return state.parsed.meta.days.findIndex(d => String(d).trim() === todayStr);
}

function showToast(message, type = 'info') {
    const container = document.getElementById('toast-container');
    const toast = document.createElement('div');
    toast.className = `toast ${type}`;

    let iconClass = 'fa-solid fa-circle-info';
    if (type === 'success') iconClass = 'fa-solid fa-circle-check';
    if (type === 'error') iconClass = 'fa-solid fa-circle-exclamation';

    toast.innerHTML = `<i class="${iconClass}"></i> <span>${message}</span>`;
    container.appendChild(toast);

    setTimeout(() => {
        toast.style.animation = 'fadeOut 0.3s ease forwards';
        setTimeout(() => toast.remove(), 300);
    }, 3000);
}

// --- UI RENDERING ---
function renderSchedule() {
    const data = state.parsed;
    const contentDiv = document.getElementById('schedule-content');

    if (!data || !data.meta || !data.workers) {
        contentDiv.innerHTML = `<div style="padding:3rem; text-align:center; color:var(--text-muted);">Brak prawidłowych danych harmonogramu. Wgraj plik JSON.</div>`;
        return;
    }

    const { days, weekdays } = data.meta;
    const todayIdx = getTodayColumnIndex();

    let tableClasses = "";
    if (state.highlightWhoOnShift) tableClasses += "highlight-who-on-shift";

    let html = `<table class="${tableClasses}"><thead><tr><th class="sticky-col" style="width: 35px;">Lp</th><th class="sticky-col-name" style="width: 140px;">Pracownik</th>`;
    days.forEach((d, i) => {
        const isWE = weekdays[i] === 'SO' || weekdays[i] === 'ND';
        const isToday = (state.highlightWhoOnShift && i === todayIdx);
        const style = isWE ? 'color:var(--highlight-color);' : '';
        const todayClass = isToday ? 'td-today-col' : '';
        html += `<th class="${todayClass}" style="${style} min-width: 32px;">${d}<br><small style="font-size:9px; opacity:0.7">${weekdays[i] || ''}</small></th>`;
    });
    html += `<th style="position: sticky; right: 0; background: var(--bg-primary); z-index: 5; border-left: 2px solid var(--border-color);">Suma</th></tr></thead><tbody>`;

    data.workers.forEach((w, wIdx) => {
        const total = calculateHours(w.shifts);
        const isSel = state.selectedWorkerIndices.has(wIdx) ? 'selected-row' : '';

        // Determine if worker is on shift today
        let isTodayShift = false;
        if (state.highlightWhoOnShift && todayIdx >= 0) {
            const shiftVal = w.shifts && w.shifts[todayIdx] ? w.shifts[todayIdx] : "";
            const code = String(shiftVal).trim().toUpperCase().replace(/\(8\)\s*$/i, '');
            if (DAY_SHIFT_CODES.has(code) || NIGHT_SHIFT_CODES.has(code)) {
                isTodayShift = true;
            }
        }
        const shiftClassRow = isTodayShift ? 'today-shift' : '';

        html += `<tr id="row-${wIdx}" class="${isSel} ${shiftClassRow}">
            <td class="sticky-col" style="text-align:center; color:var(--text-muted); font-size:10px;">${w.id}</td>
            <td class="sticky-col-name" onclick="selectWorker(${wIdx}, event)">${w.name}</td>`;

        days.forEach((_, sIdx) => {
            const val = (w.shifts && w.shifts[sIdx]) || "";
            const code = String(val).trim().toUpperCase().replace(/\(8\)\s*$/i, '');
            let cCls = "";
            if (DAY_SHIFT_CODES.has(code)) cCls = "shift-day";
            else if (NIGHT_SHIFT_CODES.has(code)) cCls = "shift-night";
            else if (code === 'U') cCls = "shift-u";
            else if (code === 'X') cCls = "shift-x";
            else if (code.startsWith('S')) cCls = "shift-s";

            // Diff with baseline
            let diff = "";
            if (state.baseline && state.baseline.workers) {
                const bVal = state.baseline.workers[wIdx]?.shifts?.[sIdx] || "";
                if (bVal === "" && val !== "") diff = "td-added";
                else if (bVal !== "" && val === "") diff = "td-removed";
                else if (bVal !== "" && val !== "" && bVal !== val) diff = "td-modified";
            }

            const isTodayCell = (state.highlightWhoOnShift && sIdx === todayIdx) ? 'td-today-col' : '';

            html += `<td class="${diff} ${isTodayCell}"><input type="text" class="shift-input ${cCls}" value="${val}" data-w="${wIdx}" data-s="${sIdx}"></td>`;
        });
        html += `<td style="text-align:center; font-weight:bold; position: sticky; right: 0; background: var(--bg); border-left: 2px solid var(--border-color); color: var(--highlight-color);">${total}</td></tr>`;
    });
    html += `</tbody></table>`;
    contentDiv.innerHTML = html;
    attachTableEvents();
}

function attachTableEvents() {
    document.querySelectorAll('.shift-input').forEach(inp => {
        inp.addEventListener('change', e => {
            const w = parseInt(e.target.dataset.w);
            const s = parseInt(e.target.dataset.s);
            if (!state.parsed.workers[w].shifts) state.parsed.workers[w].shifts = [];
            state.parsed.workers[w].shifts[s] = e.target.value;
            updateFromTable();
        });

        inp.addEventListener('focus', e => {
            e.target.select();
        });

        // Keyboard Navigation
        inp.addEventListener('keydown', e => {
            const w = parseInt(e.target.dataset.w);
            const s = parseInt(e.target.dataset.s);
            const workersCount = state.parsed.workers.length;
            const daysCount = state.parsed.meta.days.length;

            let nextW = w, nextS = s, move = false;

            switch (e.key) {
                case 'ArrowUp': nextW = w - 1; move = true; break;
                case 'Enter':
                case 'ArrowDown': e.preventDefault(); nextW = w + 1; move = true; break;
                case 'ArrowLeft':
                    if (e.target.selectionStart === 0) { nextS = s - 1; move = true; }
                    break;
                case 'ArrowRight':
                    if (e.target.selectionStart === e.target.value.length) { nextS = s + 1; move = true; }
                    break;
            }

            if (move && nextW >= 0 && nextW < workersCount && nextS >= 0 && nextS < daysCount) {
                const nextInput = document.querySelector(`.shift-input[data-w="${nextW}"][data-s="${nextS}"]`);
                if (nextInput) nextInput.focus();
            }
        });
    });
}

function updateFromTable() {
    state.content = JSON.stringify(state.parsed, null, 2);
    document.getElementById('json-editor').value = state.content;
    localStorage.setItem(STORAGE_KEY, state.content);
    renderSchedule();
    updateInspector();
    showToast("Zapisano zmiany lokalnie", "success");
}

function selectWorker(idx, event) {
    if (!(event.ctrlKey || event.metaKey)) state.selectedWorkerIndices.clear();
    if (state.selectedWorkerIndices.has(idx)) state.selectedWorkerIndices.delete(idx);
    else state.selectedWorkerIndices.add(idx);

    renderSchedule();
    updateInspector();
}

function updateInspector() {
    const dataBox = document.getElementById('inspector-data');
    const emptyBox = document.getElementById('inspector-empty');

    if (state.selectedWorkerIndices.size === 0) {
        dataBox.style.display = 'none';
        emptyBox.style.display = 'block';
        return;
    }

    dataBox.style.display = 'block';
    emptyBox.style.display = 'none';

    const idxs = Array.from(state.selectedWorkerIndices);
    if (idxs.length === 1) {
        const w = state.parsed.workers[idxs[0]];
        document.getElementById('ins-name').textContent = w.name;
        document.getElementById('ins-id').textContent = `ID: ${w.id}`;
        document.getElementById('ins-total').textContent = `${calculateHours(w.shifts)}h`;
        document.getElementById('ins-before-12').textContent = `${calculateHours(w.shifts, 11)}h`;
    } else {
        document.getElementById('ins-name').textContent = `Zaznaczono: ${idxs.length}`;
        document.getElementById('ins-id').textContent = "-";
        let total = 0, b12 = 0;
        idxs.forEach(i => {
            total += calculateHours(state.parsed.workers[i].shifts);
            b12 += calculateHours(state.parsed.workers[i].shifts, 11);
        });
        document.getElementById('ins-total').textContent = `${total}h`;
        document.getElementById('ins-before-12').textContent = `${b12}h`;
    }
}

function renderTodayView() {
    const container = document.getElementById('today-content');
    if (!state.parsed || !state.parsed.meta || !state.parsed.workers) return;

    const todayIdx = getTodayColumnIndex();
    let dateStr = new Date().toLocaleDateString('pl-PL');

    if (todayIdx < 0) {
        container.innerHTML = `<div style="padding: 2rem; text-align:center; color:var(--text-muted);">Dzisiejsza data nie mieści się w zakresie tego harmonogramu.</div>`;
        return;
    }

    let days = [], nights = [];
    state.parsed.workers.forEach(w => {
        let code = String(w.shifts[todayIdx] || "").trim().toUpperCase().replace(/\(8\)\s*$/i, '');
        if (DAY_SHIFT_CODES.has(code)) days.push(w.name);
        else if (NIGHT_SHIFT_CODES.has(code)) nights.push(w.name);
    });

    container.innerHTML = `
        <div style="padding: 1.5rem 1.5rem 0; font-size: 1.2rem; color: var(--text-primary); font-weight: 600;">
            Obsada na dziś (${dateStr})
        </div>
        <div class="today-grid">
            <div class="today-card">
                <h4 style="color:var(--shift-day); display:flex; align-items:center; gap:0.5rem; margin-bottom: 0.5rem;">
                    <i class="fa-solid fa-sun"></i> Zmiana Dzienna
                </h4>
                <ul class="today-list">${days.map(n => `<li>${n}</li>`).join('') || '<li><span style="color:var(--text-muted); font-style:italic;">Brak obsady</span></li>'}</ul>
            </div>
            <div class="today-card">
                <h4 style="color:var(--shift-night); display:flex; align-items:center; gap:0.5rem; margin-bottom: 0.5rem;">
                    <i class="fa-solid fa-moon"></i> Zmiana Nocna
                </h4>
                <ul class="today-list">${nights.map(n => `<li>${n}</li>`).join('') || '<li><span style="color:var(--text-muted); font-style:italic;">Brak obsady</span></li>'}</ul>
            </div>
        </div>
    `;
}

function renderChanges() {
    const container = document.getElementById('changes-content');
    if (!state.baseline || !state.parsed || !state.parsed.workers) {
        container.innerHTML = `<div style="padding: 2rem; color: var(--text-muted);">Brak danych referencyjnych do porównania.</div>`;
        return;
    }

    const changes = [];
    const base = state.baseline.workers;
    const cur = state.parsed.workers;
    const daysCount = state.parsed.meta?.days?.length ?? 0;

    cur.forEach((worker, w) => {
        const baseShifts = base[w]?.shifts || [];
        const curShifts = worker.shifts || [];
        const maxDays = Math.max(baseShifts.length, curShifts.length, daysCount);

        for (let s = 0; s < maxDays; s++) {
            const oldVal = String(baseShifts[s] || "").trim();
            const newVal = String(curShifts[s] || "").trim();
            if (oldVal !== newVal) {
                const type = oldVal === "" ? "added" : (newVal === "" ? "removed" : "modified");
                changes.push({ worker: worker.name, day: s + 1, type, oldVal, newVal });
            }
        }
    });

    if (changes.length === 0) {
        container.innerHTML = `<div style="padding: 3rem; text-align: center; color: var(--text-muted);">
            <i class="fa-solid fa-circle-check" style="font-size: 48px; opacity: 0.5; margin-bottom: 1rem;"></i>
            <p>Brak modyfikacji względem wersji bazowej.</p>
        </div>`;
        return;
    }

    let html = `
        <div style="padding: 1.5rem; background: var(--bg-primary); border-bottom: 1px solid var(--border-color);">
            <strong>Znaleziono zmian: <span style="color:var(--highlight-color);">${changes.length}</span></strong>
        </div>
        <table class="changes-table">
            <thead><tr><th>Pracownik</th><th>Dzień</th><th>Typ Zmiany</th><th>Z (Było)</th><th>Na (Jest)</th></tr></thead>
            <tbody>
    `;

    changes.forEach(c => {
        let typeLbl = "", typeCls = "";
        if (c.type === 'added') { typeLbl = "Dodane"; typeCls = "change-added"; }
        if (c.type === 'removed') { typeLbl = "Usunięte"; typeCls = "change-removed"; }
        if (c.type === 'modified') { typeLbl = "Zmienione"; typeCls = "change-modified"; }

        html += `<tr>
            <td>${c.worker}</td>
            <td>${c.day}</td>
            <td class="${typeCls}">${typeLbl}</td>
            <td style="color:var(--text-muted);">${c.oldVal || "—"}</td>
            <td style="font-weight:bold;">${c.newVal || "—"}</td>
        </tr>`;
    });

    html += `</tbody></table>`;
    container.innerHTML = html;
}

function renderTree() {
    const container = document.getElementById('tree-content');
    if (!state.parsed) return;

    function createNode(key, value) {
        const div = document.createElement('div');
        div.className = 'json-node';
        const type = value === null ? 'null' : Array.isArray(value) ? 'array' : typeof value;

        if (type === 'object' || type === 'array') {
            const details = document.createElement('details');
            details.open = key === 'root' || key === 'meta' || key === 'workers';
            const summary = document.createElement('summary');
            summary.innerHTML = `<span class="json-key">${key === 'root' ? '' : key + ': '}</span><span style="color:var(--text-muted)">${type === 'array' ? `Array[${value.length}]` : `Object{${Object.keys(value).length}}`}</span>`;
            details.appendChild(summary);

            Object.keys(value).forEach(k => details.appendChild(createNode(k, value[k])));
            div.appendChild(details);
        } else {
            const valClass = `json-${type}`;
            const displayVal = value === null ? 'null' : String(value);
            div.innerHTML = `<span class="json-key">${key !== 'root' ? key + ': ' : ''}</span><span class="${valClass}">${displayVal}</span>`;
        }
        return div;
    }

    container.innerHTML = '';
    container.appendChild(createNode('root', state.parsed));
}

// --- CORE ACTIONS ---
async function fetchGitHub() {
    const confirmed = await showModal("Pobieranie Danych", `Czy nadpisać lokalne dane plikiem z repozytorium ${GITHUB_REPO}?`);
    if (!confirmed) return;

    try {
        const res = await fetch(`https://raw.githubusercontent.com/${GITHUB_USER}/${GITHUB_REPO}/main/${GITHUB_FILE}`, { cache: "no-store" });
        if (!res.ok) throw new Error(`HTTP Error: ${res.status}`);
        const data = await res.json();

        state.baseline = deepCopy(data);
        state.content = JSON.stringify(data, null, 2);
        state.parsed = data;

        document.getElementById('json-editor').value = state.content;
        localStorage.setItem(STORAGE_KEY, state.content);

        renderSchedule();
        showToast("Pomyślnie pobrano dane z GitHub", "success");
    } catch (e) {
        showToast("Błąd pobierania: " + e.message, "error");
    }
}

function showModal(title, msg) {
    return new Promise(res => {
        document.getElementById('modal-title').innerHTML = `<i class="fa-solid fa-triangle-exclamation" style="color: var(--highlight-color);"></i> ${title}`;
        document.getElementById('modal-message').textContent = msg;
        const m = document.getElementById('confirmation-modal');
        m.classList.add('active');

        const clean = (val) => {
            m.classList.remove('active');
            res(val);
        };

        const btnConfirm = document.getElementById('modal-btn-confirm');
        const btnCancel = document.getElementById('modal-btn-cancel');

        // Remove old listeners to prevent multiple fires
        const newConfirm = btnConfirm.cloneNode(true);
        const newCancel = btnCancel.cloneNode(true);
        btnConfirm.replaceWith(newConfirm);
        btnCancel.replaceWith(newCancel);

        newConfirm.onclick = () => clean(true);
        newCancel.onclick = () => clean(false);
    });
}

// --- INIT ---
window.onload = () => {

    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
        try {
            state.content = saved;
            state.parsed = JSON.parse(saved);
            state.baseline = deepCopy(state.parsed);
            document.getElementById('json-editor').value = saved;
        } catch (e) {
            console.error("Corrupted local storage.");
            state.parsed = deepCopy(DEFAULT_JSON);
            state.content = JSON.stringify(state.parsed, null, 2);
        }
    } else {
        state.parsed = deepCopy(DEFAULT_JSON);
        state.content = JSON.stringify(state.parsed, null, 2);
        state.baseline = deepCopy(state.parsed);
        document.getElementById('json-editor').value = state.content;
    }

    renderSchedule();

    // View switching logic
    const views = ['schedule', 'code', 'tree', 'changes', 'today'];
    views.forEach(v => {
        document.getElementById(`btn-view-${v}`).onclick = () => {
            views.forEach(v2 => {
                document.getElementById(`view-${v2}`).classList.remove('active');
                document.getElementById(`btn-view-${v2}`).classList.remove('active');
            });
            document.getElementById(`view-${v}`).classList.add('active');
            document.getElementById(`btn-view-${v}`).classList.add('active');

            state.currentView = v;
            if (v === 'today') renderTodayView();
            if (v === 'schedule') renderSchedule();
            if (v === 'changes') renderChanges();
            if (v === 'tree') renderTree();
        };
    });

    // "Kto na zmianie" Button Toggle
    document.getElementById('btn-toggle-who').onclick = () => {
        state.highlightWhoOnShift = !state.highlightWhoOnShift;
        const label = document.getElementById('btn-who-label');
        label.textContent = state.highlightWhoOnShift ? 'Wł' : 'Wył';
        label.style.color = state.highlightWhoOnShift ? '#4ade80' : 'inherit';

        if (state.currentView === 'schedule') renderSchedule();
        showToast(state.highlightWhoOnShift ? "Włączono podgląd dzisiejszej zmiany" : "Wyłączono podgląd dzisiejszej zmiany", "info");
    };

    // Buttons
    document.getElementById('btn-cloud-load').onclick = fetchGitHub;

    document.getElementById('btn-cloud-send').onclick = () => {
        const blob = new Blob([state.content], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = GITHUB_FILE; a.click();
        showToast("Rozpoczęto pobieranie pliku dla GitHuba", "success");
    };

    document.getElementById('btn-download').onclick = () => {
        const blob = new Blob([state.content], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url; a.download = 'harmonogram_export.json'; a.click();
        showToast("Pobrano plik harmonogramu", "success");
    };

    document.getElementById('btn-save').onclick = () => {
        if (state.isValid) {
            localStorage.setItem(STORAGE_KEY, state.content);
            showToast("Zapisano dane do pamięci podręcznej", "success");
        } else {
            showToast("Nie można zapisać - JSON zawiera błędy!", "error");
        }
    };

    document.getElementById('btn-upload').onclick = () => document.getElementById('file-input').click();
    document.getElementById('file-input').onchange = (e) => {
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                state.content = ev.target.result;
                state.parsed = JSON.parse(state.content);
                state.baseline = deepCopy(state.parsed);
                document.getElementById('json-editor').value = state.content;
                renderSchedule();
                showToast("Wgrano nowy plik lokalnie", "success");
            } catch (err) {
                showToast("Błąd: Wybrany plik nie jest poprawnym formatem JSON", "error");
            }
            e.target.value = ''; // reset
        };
        if (e.target.files.length > 0) reader.readAsText(e.target.files[0]);
    };

    // JSON Editor real-time validation
    const jsonEditor = document.getElementById('json-editor');
    const dot = document.getElementById('status-dot');
    const txt = document.getElementById('status-text');

    jsonEditor.oninput = (e) => {
        try {
            state.parsed = JSON.parse(e.target.value);
            state.content = e.target.value;
            state.isValid = true;
            dot.style.background = "#28a745";
            dot.style.boxShadow = "0 0 8px #28a745";
            txt.textContent = "SYSTEM.READY";
            txt.style.color = "var(--text-muted)";
            localStorage.setItem(STORAGE_KEY, state.content);
        } catch (err) {
            state.isValid = false;
            dot.style.background = "#dc3545";
            dot.style.boxShadow = "0 0 8px #dc3545";
            txt.textContent = "SYNTAX.ERROR";
            txt.style.color = "#dc3545";
        }
    };
};
